insert into aura_exercise_catalog (id, payload, updated_at) values
  ('0FDAC0C7-12CD-581C-8D74-4E3A2B734245'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0FDAC0C7-12CD-581C-8D74-4E3A2B734245","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Chest"],"name":"Bodyweight Kneeling Triceps Extension","notes":"","plannedSets":3,"proTips":["Kneel down on the ground with your knees hip-width apart.","Place your hands on the ground in front of you, shoulder-width apart, fingers pointing forward.","Extend your legs straight behind you, balancing on your toes and hands, forming a straight line from head to heels.","Bend your elbows and lower your upper body towards the ground, keeping your elbows close to your sides.","Pause for a moment at the bottom, then push through your hands to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"83096591-815A-5AD9-9AD9-8AE474220C9C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6C3A7384-8C82-527B-A083-B1EC0FA314FF'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"6C3A7384-8C82-527B-A083-B1EC0FA314FF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Bodyweight Side Lying Biceps Curl","notes":"","plannedSets":3,"proTips":["Lie on your side with your legs extended and your head supported by your arm.","Hold your upper arm against your side and bend your elbow to curl your forearm towards your shoulder.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7ACCEE26-8C11-510E-B536-3789695EEACC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0ABBBF1D-D0CD-5D27-BB61-318F6BC66D27'::uuid, '{"category":"Back","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"0ABBBF1D-D0CD-5D27-BB61-318F6BC66D27","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Bodyweight Squatting Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding onto a sturdy object or suspension trainer with your arms extended.","Lower your body into a squat position, keeping your back straight and your knees behind your toes.","From the squat position, pull your body up towards the object or suspension trainer, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F0A77E34-D567-54D8-BF67-7E5F7F76F1BF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F7A85D0C-94B0-59BE-B6AE-74A9155DD6D0'::uuid, '{"category":"Back","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"F7A85D0C-94B0-59BE-B6AE-74A9155DD6D0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Bodyweight Squatting Row (With Towel)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a towel in front of you with your palms facing down.","Bend your knees and lower your body into a squat position, keeping your back straight and your chest up.","As you lower into the squat, simultaneously pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the squat, then slowly return to the starting position while extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B9040DF2-2511-5410-8DC0-21E053C538A9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('63139001-94A9-5A08-B363-17354B039137'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"63139001-94A9-5A08-B363-17354B039137","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles","Feet"],"name":"Bodyweight Standing Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes pointing forward.","Place your hands on a wall or stable surface for balance.","Slowly raise your heels off the ground, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"34B74515-5A35-5F5F-AD39-DB65C57CEFE9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('85A20F21-E232-59B9-8A0B-2789E3DAF8E4'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"85A20F21-E232-59B9-8A0B-2789E3DAF8E4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Bodyweight Standing Close-Grip One Arm Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand with a neutral grip.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B4546716-3884-50F3-9F3D-A1DF49F67F6C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('95248FAA-1510-5AA1-BA07-4C8E88A46E01'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"95248FAA-1510-5AA1-BA07-4C8E88A46E01","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Bodyweight Standing Close-Grip Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arms straight in front of you, gripping the bar or handles with a close grip.","Pull the bar or handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"178A39AE-174C-5358-AAAC-A18B38727F60","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2D9318A1-F473-5249-92B0-9551D479CA87'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"2D9318A1-F473-5249-92B0-9551D479CA87","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Bodyweight Standing One Arm Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand.","Bend forward at the hips, keeping your back straight and your core engaged.","Let the dumbbell hang straight down in front of you, with your arm fully extended.","Pull the dumbbell up towards your chest, keeping your elbow close to your body.","Squeeze your shoulder blades together at the top of the movement.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2F1E2937-0D0A-5E86-A668-BCB7876AC7D6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A46EE808-9076-5C0E-99D3-DB47FFC6D950'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A46EE808-9076-5C0E-99D3-DB47FFC6D950","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Bodyweight Standing One Arm Row (With Towel)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the towel back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AA8E4E91-F1FE-547B-ADEB-515CE7D56D53","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5E4E9817-3061-599A-94D7-98258FCF53F0'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"5E4E9817-3061-599A-94D7-98258FCF53F0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Bodyweight Standing Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Grasp a bar or handles with an overhand grip, palms facing down.","Keep your back straight and core engaged.","Pull the bar or handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"07D12FD7-42AE-5905-A3F4-4798516CF849","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C2A5C650-D7AF-5E35-94D9-7DCCA5FD356C'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C2A5C650-D7AF-5E35-94D9-7DCCA5FD356C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Bodyweight Standing Row (With Towel)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a towel in front of you with both hands.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8C0B1AB8-6E8E-5922-9F79-9811DD4A52C0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('15EEC22F-5C48-58A9-AF87-356854A7FE19'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"15EEC22F-5C48-58A9-AF87-356854A7FE19","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Hip Flexors"],"name":"Bottoms-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended and your arms by your sides.","Bend your knees and bring them towards your chest, keeping your feet off the ground.","Engaging your abs, lift your hips off the ground, bringing your knees towards your head.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3EA20B5E-3211-5925-A5C5-8B73486F4453","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('23D65B68-2085-520F-83FA-D3DB1F0905E4'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"23D65B68-2085-520F-83FA-D3DB1F0905E4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Quadriceps","Hamstrings","Glutes"],"name":"Box Jump Down With One Leg Stabilization","notes":"","plannedSets":3,"proTips":["Stand in front of a box or platform with your feet shoulder-width apart.","Bend your knees and jump onto the box, landing softly with one foot on the box and the other foot hanging off the edge.","Stabilize yourself on the box with the foot that is on it, while keeping the other foot off the ground.","Hold this position for a few seconds, engaging your calf muscles to maintain balance.","Slowly step down with the foot that is on the box, returning to the starting position.","Repeat the exercise with the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"08E21DF6-63A3-5E1A-84E6-D481BA52BDA0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('35108C52-E118-5E8C-97EA-82ACDF1535D7'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"35108C52-E118-5E8C-97EA-82ACDF1535D7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Glutes","Quadriceps","Hamstrings","Shoulders","Triceps"],"name":"Bridge - Mountain Climber (Cross Body)","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Engage your core and lift your right foot off the ground, bringing your right knee towards your left elbow.","Return your right foot to the starting position and repeat the movement with your left foot towards your right elbow.","Continue alternating sides, moving at a controlled pace.","Keep your hips level and avoid lifting your hips too high or sagging them too low.","Maintain a steady breathing pattern throughout the exercise.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8F028A20-364F-515B-8F45-94673AB6E4A3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5C9C129C-1A9A-55A2-95DC-629BAAD883FD'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"5C9C129C-1A9A-55A2-95DC-629BAAD883FD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves","Shoulders","Chest"],"name":"Burpee","notes":"","plannedSets":3,"proTips":["Start in a standing position with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and placing your hands on the floor in front of you.","Kick your feet back into a push-up position.","Perform a push-up, keeping your body in a straight line.","Jump your feet back into the squat position.","Jump up explosively, reaching your arms overhead.","Land softly and immediately lower back into a squat position to begin the next repetition."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('054B054C-72B3-5F59-9B34-BE3144F156AD'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"054B054C-72B3-5F59-9B34-BE3144F156AD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Butt-Ups","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands by your sides, palms facing down.","Engaging your abs, lift your legs off the ground, bringing your knees towards your chest.","At the top of the movement, squeeze your abs and pause for a moment.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2FF7066E-BF63-51E8-88B9-187AD541D4D4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('596E313F-CE3D-520C-9A84-E9CBBFA7FC33'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"596E313F-CE3D-520C-9A84-E9CBBFA7FC33","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Adductors","Hamstrings","Groin"],"name":"Butterfly Yoga Pose","notes":"","plannedSets":3,"proTips":["Sit on the floor with your legs extended in front of you.","Bend your knees and bring the soles of your feet together, allowing your knees to fall out to the sides.","Hold onto your ankles or feet with your hands.","Sit up tall and lengthen your spine.","Gently press your knees down towards the floor, feeling a stretch in your inner thighs.","Hold this position for a few breaths.","To release, slowly bring your knees back up and extend your legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"88902136-B33A-5EFA-B286-8F55FE914DA5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FFFD49CF-6594-5F54-A143-B438E13A003A'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"FFFD49CF-6594-5F54-A143-B438E13A003A","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Cable Alternate Shoulder Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and grasp the handles of the cable machine with an overhand grip.","Position your hands at shoulder height, with your palms facing forward.","Keep your core engaged and your back straight.","Press one handle up and forward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the handle back to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"800DA5C4-E619-5D39-A4FD-246BB1A9E735","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"3C2B7803-AFF5-5214-A762-5757AB631082","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6B921080-CEBD-55F8-9C86-ADB6F033C9FC'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"6B921080-CEBD-55F8-9C86-ADB6F033C9FC","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Alternate Triceps Extension","notes":"","plannedSets":3,"proTips":["Stand facing the cable machine with your feet shoulder-width apart.","Hold the cable handle with your right hand and bring your arm up so that your upper arm is parallel to the ground and your elbow is bent at a 90-degree angle.","Keep your upper arm stationary and extend your forearm backward, fully straightening your arm.","Pause for a moment, then slowly return to the starting position.","Repeat with your left arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D1680CB9-18E2-5254-8D2E-B4D556A76531","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"2A5226BC-87B5-5609-9FEE-ECAB0C9B70DB","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8D5B815E-7113-5987-978F-D25DE75A3D01'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Cable","hint":"","id":"8D5B815E-7113-5987-978F-D25DE75A3D01","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Calves"],"name":"Cable Assisted Inverse Leg Curl","notes":"","plannedSets":3,"proTips":["Adjust the cable machine so that the ankle attachment is at the lowest setting.","Lie face down on the bench with your legs straight and the ankle attachment secured to your ankles.","Hold onto the handles of the bench for stability.","Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees.","Pause for a moment at the top of the movement, squeezing your hamstrings.","Inhale and slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"9C20A47D-34C5-546A-84C7-F084DAE85C27","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"59C4AAA2-F6D2-50A1-BC3F-E98DE58DBBEC","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('35BA80A6-DB83-5CE6-8E88-5D5C975C4D91'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"35BA80A6-DB83-5CE6-8E88-5D5C975C4D91","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Cable Bar Lateral Pulldown","notes":"","plannedSets":3,"proTips":["Adjust the cable pulley to a high position and attach a straight bar.","Sit facing the cable machine with your feet flat on the ground and your knees slightly bent.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and keep your chest up, maintaining a slight arch in your lower back.","Pull the bar down towards your chest, leading with your elbows and squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"50DAAB38-9D14-5A4A-8A91-259847208893","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C615D252-BE7C-54BE-89A9-4237FCE0D96E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E829305C-4867-522A-9989-E43187DDD680'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"E829305C-4867-522A-9989-E43187DDD680","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Cable Bench Press","notes":"","plannedSets":3,"proTips":["Adjust the cable machine to chest height and attach the handles.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and step forward to create tension in the cables.","Position your feet firmly on the ground and engage your core.","Bend your elbows and bring your hands to shoulder level, keeping your elbows at a 90-degree angle.","Push the handles forward, extending your arms fully in front of you.","Pause for a moment, then slowly reverse the movement, bringing your hands back to shoulder level.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"928C96F2-041A-53E6-8749-78B41C68EC25","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B13E0169-7A41-5373-BF45-89294ADEC268","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9FFBD2F7-7DB9-55C3-99E1-813A64C43795'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"9FFBD2F7-7DB9-55C3-99E1-813A64C43795","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Close Grip Curl","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and your knees slightly bent.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Exhale and curl the bar up towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"9611FB24-BAA7-5C3B-AAFC-85B7B5B9B480","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"8EEB4AE6-FC4E-5920-A6AD-43CE6CFDCC1C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('20C19522-BBDD-5BBE-AA54-0E924B21C68E'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"20C19522-BBDD-5BBE-AA54-0E924B21C68E","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Concentration Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the floor and your knees slightly bent.","Hold the cable handle with an underhand grip and rest your elbow against the inside of your thigh.","Keeping your upper arm stationary, exhale and curl the cable handle towards your shoulder while contracting your biceps.","Pause for a moment at the top of the movement, then inhale and slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"4D0B0BFA-DA96-5B2D-A9E8-F86D030CDD69","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"0E9FE2A5-9BC6-56AD-AEE4-28419C65E398","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0AA2585F-4560-5EA2-94E0-9922F15C4B8B'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"0AA2585F-4560-5EA2-94E0-9922F15C4B8B","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Cable Concentration Extension (On Knee)","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your knees bent and feet flat on the ground.","Hold the cable handle with your right hand and place your elbow on the inside of your right knee.","Extend your arm fully, keeping your elbow stationary and close to your knee.","Pause for a moment at the top, then slowly lower your arm back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"1F372F3D-B8A4-5EF2-BB6E-D3D47907C20D","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"9B7A79BD-A2A2-562D-B38F-FC2F5314B8F5","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AFF289F4-EB66-5914-AE02-4722C2B77050'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"AFF289F4-EB66-5914-AE02-4722C2B77050","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Cable Cross-Over Lateral Pulldown","notes":"","plannedSets":3,"proTips":["Attach a cable handle to each side of a cable machine at shoulder height.","Stand in the middle of the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and step back to create tension in the cables.","Lean forward slightly from the hips, keeping your back straight and your chest up.","Pull the handles down and across your body, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"51807EA9-0DAA-53B3-9DBE-F48B190BD4EB","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"82221256-5D94-5A1D-BF4A-867DA0B1A2E8","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DB7EF5E5-6C6A-5A59-AF69-3FE5A04427B4'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"DB7EF5E5-6C6A-5A59-AF69-3FE5A04427B4","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Rhomboids","Trapezius"],"name":"Cable Cross-Over Revers Fly","notes":"","plannedSets":3,"proTips":["Attach a D-handle to each low pulley cable and stand in the middle of the cable crossover machine.","Grasp the handles with a pronated grip (palms facing down) and take a step forward, positioning your feet shoulder-width apart.","Bend your knees slightly and lean forward at the waist, keeping your back straight and your abs engaged.","With your arms extended out to the sides and slightly bent at the elbows, exhale and squeeze your shoulder blades together as you pull the cables back and upward in a reverse fly motion.","Pause for a moment at the peak contraction, then inhale and slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"40F46F9C-B858-5251-B12C-00DF3AA3C033","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"5505DE16-410F-57E5-B731-24ABC340262C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6126E276-0511-5E35-A457-DB6D18508BF9'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"6126E276-0511-5E35-A457-DB6D18508BF9","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable Cross-Over Variation","notes":"","plannedSets":3,"proTips":["Adjust the cable pulleys to chest height.","Stand in the center of the cable machine with one foot in front of the other.","Grasp the handles with your palms facing down and your arms extended out to the sides.","Take a step forward, keeping your arms slightly bent.","With a slight bend in your elbows, bring your hands together in front of your chest.","Pause for a moment, then slowly return your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"406C7BD2-F2C6-55E6-97A6-92711F33B532","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"F99A49B4-F87A-5D23-8246-1FFBAB574823","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E4964F58-FF34-5D00-A09B-810E19100FC7'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"E4964F58-FF34-5D00-A09B-810E19100FC7","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Curl","notes":"","plannedSets":3,"proTips":["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable attachment with an underhand grip, palms facing up.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the cable attachment towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"783DF181-5A41-54D3-B7A4-F46CF64AE02B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"618626F9-A3A3-528F-BB71-5348E592555A","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E28B26FF-FD48-5DC8-80B0-6E563E378C12'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Cable","hint":"","id":"E28B26FF-FD48-5DC8-80B0-6E563E378C12","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Lower Back"],"name":"Cable Deadlift","notes":"","plannedSets":3,"proTips":["Stand facing the cable machine with your feet shoulder-width apart.","Bend at the hips and knees, lowering your torso until your back is parallel to the ground.","Grasp the cable handles with an overhand grip, keeping your arms straight and your shoulders back.","Engage your glutes and hamstrings to lift the cable handles, extending your hips and standing up straight.","Pause for a moment at the top, then slowly lower the cable handles back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"91CBB082-8513-5F63-80AB-4660E8BFED65","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B5188E7E-FF3A-5F20-A96A-DE71867FCA01","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('06D804AE-D21C-5636-8D3D-0AE6970109BF'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"06D804AE-D21C-5636-8D3D-0AE6970109BF","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Cable Decline Fly","notes":"","plannedSets":3,"proTips":["Adjust the cable machine to a decline position.","Stand facing away from the machine with your feet shoulder-width apart.","Hold the handles with your palms facing forward and your arms extended straight out in front of you.","Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.","Pause for a moment at the fully extended position, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"6FD8E221-55FC-5413-BD1C-C43E52037A64","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"721EEBDD-2698-5555-9A1D-33A86797CD5E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EDFDD8E7-AB00-509A-807F-18242BBAF82E'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"EDFDD8E7-AB00-509A-807F-18242BBAF82E","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Cable Decline One Arm Press","notes":"","plannedSets":3,"proTips":["Adjust the cable machine to a decline position.","Stand facing away from the machine and grab the handle with one hand.","Position yourself with your back against the decline bench and your arm extended straight in front of you.","Bend your elbow and lower the handle towards your chest while keeping your upper arm stationary.","Pause for a moment at the bottom, then push the handle back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D0789125-E5FD-5EE4-888D-14A928B94C51","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"622D6323-E0B1-51A0-8CF7-295F7244C06C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4954C925-F933-5075-BB46-209C2431F763'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"4954C925-F933-5075-BB46-209C2431F763","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Cable Decline Press","notes":"","plannedSets":3,"proTips":["Adjust the cable machine to a decline position.","Sit on the decline bench facing the cable machine.","Grasp the handles with an overhand grip and position them at chest level.","Keep your feet flat on the ground and your back firmly against the bench.","Exhale and push the handles away from your body, extending your arms fully.","Pause for a moment at the end of the movement, squeezing your chest muscles.","Inhale and slowly return the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"21F10F21-A66C-59FF-A949-BC95A5CBB51C","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"A0B84257-5F41-55A2-9F4C-816EE6506086","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E17232A1-E463-5750-8A2A-D301B91297BD'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"E17232A1-E463-5750-8A2A-D301B91297BD","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Decline Seated Wide-Grip Row","notes":"","plannedSets":3,"proTips":["Sit on the decline bench facing the cable machine with your feet securely placed on the footrests.","Grasp the cable attachment with a wide overhand grip, palms facing down.","Lean back slightly, keeping your back straight and your core engaged.","Pull the cable towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"268B0289-97B5-57FE-A952-A7D760AD19DF","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"0F1AE980-CDA7-5BC4-8E03-B8CC76C6AE2E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4FFFC04E-EB41-5EA2-9D1C-94E8BED8F4D2'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"4FFFC04E-EB41-5EA2-9D1C-94E8BED8F4D2","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Drag Curl","notes":"","plannedSets":3,"proTips":["Stand facing a cable machine with your feet shoulder-width apart.","Grasp the cable attachment with an underhand grip, palms facing up, and arms fully extended.","Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders by contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"1C6165A5-4CB5-5CC9-993F-476675301E4C","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"26C48ED8-04D5-512C-8BE2-D45ADB317B5D","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4CB81914-1D93-52D1-B6CC-87A949ED0206'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"4CB81914-1D93-52D1-B6CC-87A949ED0206","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Floor Seated Wide-Grip Row","notes":"","plannedSets":3,"proTips":["Sit on the floor with your legs extended and your back straight.","Attach a cable handle to a low pulley and position the cable machine behind you.","Grasp the handle with a wide overhand grip, palms facing down.","Lean back slightly, keeping your back straight and your chest lifted.","Pull the handle towards your waist, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the handle back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"DC3EFAFF-5473-5467-BC4F-A5EDAB039840","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"1F0C5A6A-5A8D-560E-AF7D-2F912BC15823","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('52A6B091-16C2-53F4-9674-CD01E200959C'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"52A6B091-16C2-53F4-9674-CD01E200959C","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Forearms"],"name":"Cable Forward Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Hold the cable handle with an overhand grip, palms facing down, and your arms fully extended in front of you.","Keeping your arms straight, raise the cable handle up to shoulder level.","Pause for a moment at the top, then slowly lower the cable handle back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"8135A343-C935-562E-8C76-FE59DE702688","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"A3726650-E7D1-5DFC-B58E-29EBFDF20FB7","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9867F429-5BA4-5B6A-8F2D-FA32B9AC99C5'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"9867F429-5BA4-5B6A-8F2D-FA32B9AC99C5","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Forearms"],"name":"Cable Front Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip.","Keep your back straight and your core engaged.","Raise the cable handle in front of you, keeping your arms straight and your palms facing down.","Continue lifting until your arms are parallel to the floor.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"6608E30E-3744-5CB0-987C-1C9E5C50152A","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C838CB01-CD29-515D-B4BE-521A36C837A0","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3A5200C6-AC39-5DD5-A3CE-4A5CCCF45D3F'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"3A5200C6-AC39-5DD5-A3CE-4A5CCCF45D3F","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Biceps"],"name":"Cable Front Shoulder Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip.","Keep your back straight and your core engaged.","Raise the cable handle in front of you, keeping your arms straight and your palms facing down.","Continue lifting until your arms are parallel to the floor.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"FA0DB597-3C31-5B7C-A480-E34262A84DD8","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"FB75C73E-8046-577D-97A9-E49C4123C43C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('542EAE90-5A0C-5809-8245-F55255F9D373'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"542EAE90-5A0C-5809-8245-F55255F9D373","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Hammer Curl (With Rope)","notes":"","plannedSets":3,"proTips":["Stand upright with your feet shoulder-width apart and a slight bend in your knees.","Hold the cable rope attachment with an underhand grip, palms facing each other, and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the cable rope attachment until your biceps are fully contracted and the rope is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the cable rope attachment back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"DF619858-2234-559F-8DF3-6816E64A9EF3","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"1C6DBC3A-FBF7-597F-BCA1-BA38F26EEA68","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('13D9DB3C-B60B-57A3-95A1-82104EAB0FD4'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Cable","hint":"","id":"13D9DB3C-B60B-57A3-95A1-82104EAB0FD4","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable High Pulley Overhead Tricep Extension","notes":"","plannedSets":3,"proTips":["Attach a rope to a high pulley and stand facing away from the machine.","Grasp the rope with both hands and extend your arms overhead.","Keep your elbows close to your head and your upper arms stationary.","Slowly lower the rope behind your head by bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"DAFC93FE-00B3-5488-8E14-266824190183","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C29B9D39-BEFA-5589-A2A7-5CED19124AD6","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4AAD0441-ACD2-5F57-8C89-3DBCC4A0E0C0'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"4AAD0441-ACD2-5F57-8C89-3DBCC4A0E0C0","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Cable High Row (Kneeling)","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a cable machine at chest height.","Kneel down in front of the cable machine and grab the bar with an overhand grip, hands shoulder-width apart.","Sit back on your heels, keeping your back straight and your core engaged.","Pull the bar towards your upper abdomen, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"8EA9C448-CDFF-5AF2-AAD6-9570983B070F","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"BA3E3AAD-2616-50B9-8762-6ED20BAFD805","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6AA4BCBD-F0B6-511E-9181-9EFDC43900B1'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Cable","hint":"","id":"6AA4BCBD-F0B6-511E-9181-9EFDC43900B1","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Adductors","Glutes","Quadriceps"],"name":"Cable Hip Adduction","notes":"","plannedSets":3,"proTips":["Attach the ankle cuff to your ankle and stand facing the cable machine.","Position yourself far enough away from the machine so that there is tension on the cable.","Place your hands on the machine for support.","Keeping your leg straight, slowly move your leg across your body towards the midline.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"EFD4DF4D-804E-5050-9B36-BAA14C208909","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"F1117272-5EC0-57D1-B068-F5FA00B9E473","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3CDA49A2-62FD-5EB3-AA0C-CBA4B3728203'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"3CDA49A2-62FD-5EB3-AA0C-CBA4B3728203","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable Incline Bench Press","notes":"","plannedSets":3,"proTips":["Adjust the bench to a 45-degree incline.","Attach the cable handles to the high pulleys.","Sit on the bench facing the cable machine with your feet flat on the ground.","Grasp the handles with an overhand grip and bring them to shoulder height.","Push the handles forward and upward until your arms are fully extended.","Pause for a moment, then slowly lower the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"2D73C2FB-58B0-53A7-B07E-583DF896540F","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"03FDDD10-9174-5D95-9891-A481860D2E9D","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('35FA83CF-B281-5233-8F04-B2E6F5209FDF'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"35FA83CF-B281-5233-8F04-B2E6F5209FDF","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Rear Deltoids"],"name":"Cable Incline Bench Row","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle and attach a cable handle to the low pulley.","Sit on the bench facing the cable machine with your feet flat on the floor and your knees slightly bent.","Grasp the cable handle with an overhand grip and extend your arms fully in front of you.","Lean forward from your hips while keeping your back straight and your core engaged.","Pull the cable handle towards your chest by retracting your shoulder blades and bending your elbows.","Squeeze your back muscles at the top of the movement, then slowly extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"53C7CE61-07EF-593F-8E01-021639780C82","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"302D7E1A-1295-566A-B189-37A08E232AD7","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('61493BC9-23F9-5688-95C2-B2DD2315D086'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"61493BC9-23F9-5688-95C2-B2DD2315D086","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable Incline Fly","notes":"","plannedSets":3,"proTips":["Adjust the cable machine to a low position and attach the handles.","Sit on an incline bench with your back against the pad and feet flat on the floor.","Grasp the handles with an overhand grip and extend your arms straight out in front of you.","Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.","Pause for a moment at the fully extended position, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"27B601F9-0A34-5D3F-91D9-B45EA5B95D56","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"76C35B4D-DF58-5A1F-8CE8-A30EEED8828B","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1F330E98-422E-5459-B7FA-F3560731EE4A'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"1F330E98-422E-5459-B7FA-F3560731EE4A","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable Incline Fly (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Set up a stability ball at an incline angle.","Attach the cable handles to the high pulleys of a cable machine.","Sit on the stability ball facing away from the machine, with your feet firmly planted on the ground.","Grasp the cable handles with an overhand grip, palms facing forward.","Lean forward slightly, keeping your back straight and core engaged.","With a controlled motion, bring your arms out to the sides, keeping a slight bend in your elbows.","Continue the motion until your arms are parallel to the ground.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"2B4872B5-7737-5328-8C6E-51D4AAE70831","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"3C148AD0-6748-5338-8B06-950383D37994","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7AC12637-D22A-5B26-A383-6A2525AA5F38'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"7AC12637-D22A-5B26-A383-6A2525AA5F38","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Triceps","Shoulders"],"name":"Cable Incline Pushdown","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a high pulley cable machine.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.","Lean forward slightly and keep your back straight.","Pull the bar down towards your thighs by extending your elbows.","Pause for a moment at the bottom, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"75C86397-734E-5672-AD2E-4EEB69A30B51","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"7246579A-2B6C-5A83-A334-3D13777DFA2A","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('286E3C9C-B975-5605-81B7-291850D4E581'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"286E3C9C-B975-5605-81B7-291850D4E581","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Incline Triceps Extension","notes":"","plannedSets":3,"proTips":["Adjust the cable machine to a low pulley position.","Attach a straight bar to the cable.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip and extend your arms straight overhead.","Lean forward slightly, keeping your back straight and core engaged.","Bend your elbows and lower the bar behind your head, keeping your upper arms close to your ears.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"4E641A1B-3DE0-58AA-8A5F-D4E88CD4E7FE","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"90375754-B416-5579-840B-19A42C8D2C48","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0F2F63EC-720D-5D32-9F91-490819B9B344'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"0F2F63EC-720D-5D32-9F91-490819B9B344","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Shoulders"],"name":"Cable Judo Flip","notes":"","plannedSets":3,"proTips":["Stand facing the cable machine with your feet shoulder-width apart.","Hold the cable handle with both hands at chest level, palms facing down.","Engage your core and rotate your torso to the right, pulling the cable across your body.","As you rotate, pivot your back foot and allow your hips to rotate naturally.","Extend your arms fully and finish the movement by flipping the cable handle over your shoulder.","Return to the starting position by reversing the movement, rotating your torso back to the center.","Repeat the movement on the opposite side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"027BF9ED-E808-5150-AA95-BD98AF759373","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4AF37EF2-F4E8-5DE9-A325-8BD5FA39A868","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9A86C516-282E-5B95-941A-57551D9B63B4'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"9A86C516-282E-5B95-941A-57551D9B63B4","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Kickback","notes":"","plannedSets":3,"proTips":["Stand facing a cable machine with your feet shoulder-width apart.","Hold the cable handle with your right hand and step back to create tension in the cable.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Keep your upper arm close to your body and your elbow bent at a 90-degree angle.","Extend your forearm backward, straightening your arm fully.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"23E8DA68-4904-5074-A906-87C9D0129AD1","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4EA4C482-B8FA-55B3-AD2B-865409D8D04E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E7F4A67A-41AC-5179-B23E-2ECB4256CAEC'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"E7F4A67A-41AC-5179-B23E-2ECB4256CAEC","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Cable Kneeling Crunch","notes":"","plannedSets":3,"proTips":["Attach a rope handle to a high pulley and kneel down facing away from the machine.","Hold the rope handle with both hands and place it behind your head, keeping your elbows out to the sides.","Keeping your hips stationary, flex your waist and crunch your torso down towards your thighs.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"44BA01B1-16FE-5387-B412-A231D48B6170","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"EF718117-C361-50A6-A450-576916240912","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A8B23D29-70BA-59E2-8933-B4B2478EA91D'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"A8B23D29-70BA-59E2-8933-B4B2478EA91D","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids","Biceps"],"name":"Cable Kneeling Rear Delt Row (With Rope)","notes":"","plannedSets":3,"proTips":["Attach a rope handle to a low cable pulley and kneel down facing the machine.","Grasp the rope with a neutral grip (palms facing each other) and extend your arms fully in front of you.","Keeping your back straight and core engaged, pull the rope towards your body by retracting your shoulder blades.","Squeeze your shoulder blades together at the end of the movement and hold for a brief pause.","Slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"89375496-C574-5B34-8BA2-B52F018642D2","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"486EC5C1-0CF0-5FD9-B0B8-94B539E2146F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BC0CA457-2146-5350-B9EB-9DD93E6A21AE'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"BC0CA457-2146-5350-B9EB-9DD93E6A21AE","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Kneeling Triceps Extension","notes":"","plannedSets":3,"proTips":["Attach a rope handle to a high pulley and kneel down facing the cable machine.","Grasp the rope with a neutral grip (palms facing each other) and bring your hands to the sides of your head.","Keep your elbows close to your head and your upper arms stationary throughout the exercise.","Extend your forearms by contracting your triceps until your arms are fully extended.","Pause for a moment, then slowly return to the starting position by bending your elbows.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"2007DD98-74FE-5C82-9B72-6147A8573C9E","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"531505B3-8D6A-53CA-955C-091F78EFC03B","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0E456625-E404-5BD5-BECC-337BCC2BDDEE'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"0E456625-E404-5BD5-BECC-337BCC2BDDEE","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Cable Lat Pulldown Full Range Of Motion","notes":"","plannedSets":3,"proTips":["Sit on the lat pulldown machine with your knees positioned under the pads.","Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and keep your chest up, maintaining a slight arch in your lower back.","Pull the bar down towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B7A40007-7E97-5CD8-A471-F60DD8C4A97F","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"9D483027-E96D-56B2-9D97-6BE3470B9B09","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9178055F-8CDA-5D95-AEC5-5AF57AAA7193'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"9178055F-8CDA-5D95-AEC5-5AF57AAA7193","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Cable Lateral Pulldown (With Rope Attachment)","notes":"","plannedSets":3,"proTips":["Attach a rope attachment to the cable machine at a high position.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with an overhand grip, palms facing each other.","Keep your back straight and lean slightly back.","Pull the rope down towards your sides, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement.","Slowly release the tension and allow the rope to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"96473CEA-0B5D-56B4-95B9-62DBC5C2B2B9","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4B99DAF6-F9F1-531D-BE01-8428F9E607A8","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('00A3DCD9-FF1D-5735-BBFA-CCA51C061E0C'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"00A3DCD9-FF1D-5735-BBFA-CCA51C061E0C","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Cable Lateral Pulldown With V-Bar","notes":"","plannedSets":3,"proTips":["Sit down on the cable pulldown machine and grab the v-bar attachment with an overhand grip.","Adjust the knee pad so that your thighs are secured under it.","Keep your back straight and lean back slightly.","Pull the v-bar down towards your upper chest while keeping your elbows close to your body.","Squeeze your back muscles at the bottom of the movement.","Slowly return the v-bar to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"42ED7876-C101-5AA3-99CF-D352026E825B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"11AE26C1-B2C4-5E8E-B3CF-88B0032B91E1","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DC7A9835-F190-5EA9-A527-88E7C275D95E'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"DC7A9835-F190-5EA9-A527-88E7C275D95E","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Triceps"],"name":"Cable Lateral Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and grasp the cable handles with an overhand grip.","Keep your arms straight and your core engaged.","Raise your arms out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"1DED1ED1-442C-56F4-A312-1584CDF41B82","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4188209B-491C-577B-A9C9-CCB95961C381","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('08878CE5-2787-50B2-B169-14477EBA949F'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"08878CE5-2787-50B2-B169-14477EBA949F","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable Low Fly","notes":"","plannedSets":3,"proTips":["Attach the handles to the low pulleys of a cable machine and select an appropriate weight.","Stand in the middle of the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the handles with an overhand grip and extend your arms out to the sides, keeping a slight bend in your elbows.","Maintaining control, slowly bring your arms forward in a sweeping motion, crossing them in front of your body.","Pause for a moment at the peak of the movement, feeling the stretch in your chest muscles.","Reverse the motion and slowly return your arms to the starting position, keeping tension on your chest muscles throughout.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"ADEBCCFB-853E-5BBB-A0D4-DC944E416ABD","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"1B2B1EE2-DB31-5DF1-891D-ED7CD4D08A1F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('32C9D1BB-448C-5726-9005-54A7D7845345'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"32C9D1BB-448C-5726-9005-54A7D7845345","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Low Seated Row","notes":"","plannedSets":3,"proTips":["Sit on the machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handles with an overhand grip, palms facing down.","Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"0183676F-7877-5587-AA8C-997B980184AA","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"CEA201A7-9DBD-5CE7-832C-6255F4E4917C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6CD306DD-AD9F-5F7A-926C-22CEC6D1C162'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"6CD306DD-AD9F-5F7A-926C-22CEC6D1C162","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Lying Bicep Curl","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a low pulley cable machine.","Lie face up on a flat bench with your feet flat on the ground.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Extend your arms fully, keeping your elbows close to your sides.","Keeping your upper arms stationary, exhale and curl the bar up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"28F9E54F-CC30-5A01-8FB4-38E470728045","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C1CD2423-C9E9-555E-B477-9C2BCA80A9F8","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1BE31EDB-A1F9-5A82-A113-DB279A8F2D73'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"1BE31EDB-A1F9-5A82-A113-DB279A8F2D73","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Lying Close-Grip Curl","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a low pulley cable machine.","Lie face up on a flat bench with your feet flat on the ground.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Extend your arms fully, keeping your elbows close to your sides.","Keeping your upper arms stationary, curl the bar towards your chest by contracting your biceps.","Pause for a moment at the top, squeezing your biceps.","Slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"5AE98CAF-FCC4-5F3F-887E-2356D5879ED9","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"98040ED9-C295-56C0-99B6-52CC2C338A79","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('24B23B88-5C48-50F5-AC99-98D1CB9DBF03'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"24B23B88-5C48-50F5-AC99-98D1CB9DBF03","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Triceps","Shoulders"],"name":"Cable Lying Extension Pullover (With Rope Attachment)","notes":"","plannedSets":3,"proTips":["Attach a rope to a cable machine and set the pulley at the highest position.","Lie down on a bench with your head towards the cable machine.","Hold the rope with both hands and extend your arms straight up above your chest.","Keeping your arms straight, slowly lower the rope behind your head while maintaining control.","Pause for a moment at the bottom, then slowly raise the rope back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"A3372694-C76C-5846-8C6E-59BD786C09EA","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"EF13286C-E575-55B4-8CB7-E7CC1258A49C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8103D8A8-C4C4-564F-81FF-6A9F6CC8C946'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"8103D8A8-C4C4-564F-81FF-6A9F6CC8C946","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable Lying Fly","notes":"","plannedSets":3,"proTips":["Attach the handles to the cables and lie flat on a bench with your feet flat on the ground.","Hold the handles with your palms facing each other and your arms extended straight above your chest.","Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D296F0D6-9859-551C-95C6-24B610B9340C","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"446E705D-C610-53D9-9274-6A732E5C33A7","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C15A561C-9880-5858-B8EE-F25657082242'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"C15A561C-9880-5858-B8EE-F25657082242","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Lying Triceps Extension V. 2","notes":"","plannedSets":3,"proTips":["Attach a rope handle to a low pulley cable machine.","Lie down on a flat bench facing up, with your head towards the cable machine.","Grasp the rope handle with both hands, palms facing each other, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the rope handle towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"00FF588E-53C6-58CF-9FF8-BF40C4477FDA","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"6E38C679-BF9A-515A-87CF-1070F7133DE2","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D8F38EA3-1022-5F7D-804B-21D5FB9209E6'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"D8F38EA3-1022-5F7D-804B-21D5FB9209E6","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable Middle Fly","notes":"","plannedSets":3,"proTips":["Attach cables to both sides of a cable machine at chest height.","Stand in the center of the machine with one foot slightly in front of the other.","Grasp the handles with an overhand grip and extend your arms out to the sides.","Keep a slight bend in your elbows and maintain a slight forward lean.","Engage your chest muscles and bring your arms forward in a sweeping motion.","Pause for a moment at the center, then slowly return your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"983BAF65-8B58-584C-A4CC-66E519211312","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"EAC0A53C-7E11-513A-A65F-41FF07E14ABE","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9CA47981-FA45-56D5-B034-871988D1D6F7'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"9CA47981-FA45-56D5-B034-871988D1D6F7","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable One Arm Bent Over Row","notes":"","plannedSets":3,"proTips":["Stand facing a cable machine with your feet shoulder-width apart.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Grasp the cable handle with one hand, palm facing inward, and extend your arm fully.","Pull the cable handle towards your body, keeping your elbow close to your side, until your hand reaches your lower chest.","Pause for a moment, then slowly extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"A56F5954-0D13-5C6E-85B3-975C959DB8B8","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"6FA405E8-90D1-5826-8E24-64BAB58D63E1","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0BA73F17-325A-5586-9DD6-90E646C896D4'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"0BA73F17-325A-5586-9DD6-90E646C896D4","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable One Arm Curl","notes":"","plannedSets":3,"proTips":["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip, palm facing up.","Keep your elbow close to your side and slowly curl your forearm up towards your shoulder.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"BFE0AF08-8B4B-5784-8032-61ACBB5AB0DD","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"7275980B-E1CB-5918-9FF7-41C7ABE4F234","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F9E9F39C-9A59-5E83-9CD2-AF96A11B00AF'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"F9E9F39C-9A59-5E83-9CD2-AF96A11B00AF","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Cable One Arm Decline Chest Fly","notes":"","plannedSets":3,"proTips":["Attach a D-handle to a low pulley cable machine and set the bench to a decline angle.","Lie down on the bench with your head towards the machine and grab the handle with your right hand.","Extend your arm straight up above your chest, keeping a slight bend in your elbow.","With a controlled motion, lower your arm out to the side until your hand is in line with your shoulder.","Pause for a moment, then reverse the motion and bring your arm back to the starting position.","Repeat for the desired number of repetitions, then switch to your left arm and repeat the exercise."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"E2766BA8-B403-5B7F-AD17-7DD3650B48F5","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"208BBE2F-1088-5B0D-A7F1-90D9888541DB","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9B996953-39A6-539B-BD25-56A6E8459785'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"9B996953-39A6-539B-BD25-56A6E8459785","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable One Arm Fly On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a cable handle in one hand and extend your arm out to the side, parallel to the ground.","Keep your elbow slightly bent and your palm facing forward.","Slowly bring your arm across your body, squeezing your chest muscles.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"AF085B77-BBAF-5649-BA0E-7A6790821FE6","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"8D026444-A4EE-5453-B233-EEAC455BA58A","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8240C0BF-E2D7-551B-8C9B-38F3225B7A31'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"8240C0BF-E2D7-551B-8C9B-38F3225B7A31","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable One Arm Incline Fly On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back against an incline bench.","Hold a cable handle in one hand with your arm extended and palm facing inward.","Keeping a slight bend in your elbow, slowly lower your arm out to the side until your hand is in line with your shoulder.","Pause for a moment, then squeeze your chest muscles to bring your arm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"54A1469A-6CFC-5F7E-8DD3-B1448021B963","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"F49341B5-4020-5F7B-9F66-BAE72288343E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C5236BE0-BE3E-5734-8F8A-039558CE5233'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"C5236BE0-BE3E-5734-8F8A-039558CE5233","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable One Arm Incline Press","notes":"","plannedSets":3,"proTips":["Adjust the cable machine to a low pulley position.","Sit on an incline bench facing away from the cable machine.","Grasp the handle with one hand and bring it up to shoulder height.","Position your feet firmly on the ground and maintain a stable position.","Press the handle forward and upward, extending your arm fully.","Pause for a moment at the top, then slowly lower the handle back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"DB416E41-8DA5-5DEA-AE8C-DD12A815CBAF","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"8C97B77C-ACF3-5E50-9656-66378AE758F6","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EC72EDB7-0814-5DB6-9820-E6A9FBE11181'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"EC72EDB7-0814-5DB6-9820-E6A9FBE11181","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Cable One Arm Incline Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back resting against an incline bench.","Hold a cable handle in one hand and position your arm at a 90-degree angle with your elbow bent.","Press the cable handle forward and upward, extending your arm fully.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"77463583-74DB-513E-BDEE-27595D9B753B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"7E0EC78C-4FF2-52A9-8DFC-7C7A017B25BD","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D4DA94B7-B32E-53C4-9D1A-5486FF52D5B3'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"D4DA94B7-B32E-53C4-9D1A-5486FF52D5B3","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Trapezius"],"name":"Cable One Arm Lateral Bent-Over","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, facing a cable machine.","Grasp the handle with one hand and step back to create tension on the cable.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arm out to the side, parallel to the ground, with a slight bend in your elbow.","Slowly bring your arm back to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"C6AEBCF5-C36D-500C-A21C-746AFC347BF1","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"DD7D7842-4019-5BB6-B383-5A87F4AFDA2D","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EDD40189-FA5B-5233-B27E-454C495927A8'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"EDD40189-FA5B-5233-B27E-454C495927A8","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Triceps"],"name":"Cable One Arm Lateral Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with one hand, palm facing down, and stand far enough away from the machine so that there is tension on the cable.","Keep your arm straight and slowly raise it out to the side until it is parallel to the ground.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"60C145F2-2B89-5432-9417-EE6BEA228735","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"3E4986FF-75B7-519E-867C-80DE05402C29","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AFD6E0D7-6C82-592B-89FB-B3DAA9EF4050'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"AFD6E0D7-6C82-592B-89FB-B3DAA9EF4050","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable One Arm Preacher Curl","notes":"","plannedSets":3,"proTips":["Adjust the cable machine so that the preacher curl pad is at chest height.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip and position your upper arm against the preacher curl pad.","Keep your back straight and your core engaged.","Slowly curl the cable handle towards your shoulder, keeping your upper arm against the pad.","Pause for a moment at the top of the movement, squeezing your biceps.","Slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions.","Switch arms and repeat the exercise."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"0EA06669-2B58-56DF-B20E-19778C00B9C8","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"08B943C3-BA3D-5E31-ADED-D41655D40A74","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('40DD7D31-176F-5950-8260-8C33A11E911E'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"40DD7D31-176F-5950-8260-8C33A11E911E","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Cable One Arm Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a cable handle in one hand and position your arm at chest height, elbow bent.","Place your other hand on your hip for stability.","Press the cable handle forward, extending your arm fully.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"020C388F-80B6-5843-B4A5-2739E64F67EC","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"214820CE-008F-5033-9696-ED5DFC783F8E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EA10D84F-C78B-5712-8A3A-4AD2B3D44C69'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"EA10D84F-C78B-5712-8A3A-4AD2B3D44C69","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Cable One Arm Pulldown","notes":"","plannedSets":3,"proTips":["Attach a single handle to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the handle with an overhand grip and extend your arm fully.","Keep your back straight and your core engaged.","Pull the handle down towards your side while keeping your elbow close to your body.","Pause for a moment at the bottom of the movement, squeezing your lat muscle.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions.","Switch sides and repeat the exercise with the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"8F408A80-CEB5-5732-95EF-3873B1B99499","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"1BAA5981-D5BB-5047-8E11-8FE20CEA176A","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('87408393-CE0A-5D5D-A6CE-940B5D237C23'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"87408393-CE0A-5D5D-A6CE-940B5D237C23","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable One Arm Reverse Preacher Curl","notes":"","plannedSets":3,"proTips":["Adjust the cable machine so that the pulley is at the lowest position.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip and position your upper arm against the preacher bench pad.","Keep your back straight and your core engaged throughout the exercise.","Slowly curl your forearm towards your bicep, keeping your upper arm stationary against the pad.","Pause for a moment at the top of the movement, squeezing your bicep.","Slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions.","Switch arms and repeat the exercise."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"BE5052CA-68C9-5845-ACAA-392564A29DF7","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"644C29E5-0DC6-5ADD-9BC7-BD987F3B8D34","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('684FB442-0516-5C68-BE87-923120B4EEE8'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"684FB442-0516-5C68-BE87-923120B4EEE8","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Cable One Arm Straight Back High Row (Kneeling)","notes":"","plannedSets":3,"proTips":["Attach a handle to a cable machine at waist height.","Kneel down facing the cable machine and grab the handle with one hand.","Keep your back straight and your core engaged.","Pull the handle towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions.","Switch sides and repeat the exercise with the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"A17F9101-DC08-599C-976B-D362D69A478A","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"AF592C1B-4F37-58CE-9EDD-31463CD83E5D","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3365410A-6361-59EB-9BBA-2CD9811084D3'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"3365410A-6361-59EB-9BBA-2CD9811084D3","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Cable One Arm Tricep Pushdown","notes":"","plannedSets":3,"proTips":["Stand facing a cable machine with a straight bar attachment at chest height.","Grasp the bar with an overhand grip and step back to create tension in the cable.","Position your feet shoulder-width apart and slightly bend your knees.","Keep your back straight and core engaged throughout the exercise.","Start with your arm fully extended and perpendicular to the floor.","Keeping your upper arm stationary, exhale and push the bar down until your arm is fully extended.","Pause for a moment, then inhale and slowly return to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B5EA801F-D584-54CD-B127-F8464AFCC6FA","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"9D816C33-6CDA-52AB-BC1C-773C5B222139","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EC04E844-20A1-58E9-9BC4-D265660DF506'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Cable","hint":"","id":"EC04E844-20A1-58E9-9BC4-D265660DF506","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Cable Overhead Curl","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the bar down towards your forehead, keeping your upper arms stationary.","Pause for a moment at the bottom of the movement, squeezing your biceps.","Inhale and slowly return the bar to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"BD102E3A-2C92-5681-A03A-7CEE99727EEA","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"AA1D5978-239C-55EE-B14A-AEE646F2BF2E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B969F510-9F77-554A-9A3D-5B9304C98E63'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Cable","hint":"","id":"B969F510-9F77-554A-9A3D-5B9304C98E63","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Cable Overhead Curl On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball and hold the cable handle with an underhand grip.","Extend your arms fully overhead, keeping your elbows close to your ears.","Slowly curl the cable down towards your forehead, keeping your upper arms stationary.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"4787D3D6-26A8-5BB7-9557-98532BCD67B3","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"21362D5B-E2C5-5A94-8F2A-ED45BD2FD23E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DB248F19-276C-5613-851B-9AF5E3F0BD33'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Cable","hint":"","id":"DB248F19-276C-5613-851B-9AF5E3F0BD33","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Overhead Triceps Extension (Rope Attachment)","notes":"","plannedSets":3,"proTips":["Attach a rope to a cable machine at a high position.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the rope with both hands, palms facing each other, and bring your hands above your head.","Keep your upper arms close to your head and your elbows pointing forward.","Slowly lower the rope behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"50AF9CC3-871B-59B9-87E4-AD0B7E785C46","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"6F3A1C4C-D854-5FF6-A824-35F2DD8B36F0","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A8498A9C-3184-50E1-AE5B-2D5DC2B414E8'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"A8498A9C-3184-50E1-AE5B-2D5DC2B414E8","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Palm Rotational Row","notes":"","plannedSets":3,"proTips":["Attach a handle to a cable machine at waist height.","Stand facing the machine with your feet shoulder-width apart.","Grasp the handle with an overhand grip, palms facing down.","Step back to create tension on the cable, keeping your back straight and knees slightly bent.","Pull the handle towards your body, rotating your palms to face upwards as you do so.","Squeeze your shoulder blades together at the end of the movement.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"F1591A85-BF06-538B-A8E8-1B24E311EB7A","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('909C5872-4EDA-59BC-8055-C5AB68640E9E'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"909C5872-4EDA-59BC-8055-C5AB68640E9E","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Preacher Curl","notes":"","plannedSets":3,"proTips":["Adjust the cable machine so that the preacher curl pad is at chest height.","Sit on the preacher curl bench and place your upper arms on the pad, gripping the cable attachment with an underhand grip.","Keep your back straight and your elbows tucked in at your sides.","Slowly curl the cable attachment up towards your shoulders, squeezing your biceps at the top of the movement.","Pause for a moment, then slowly lower the cable attachment back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"614DF66F-98C7-5874-9D84-A1202F0E33AA","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"E31CA159-1731-512D-B902-742637DAEB85","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2A2D5BA8-6AC6-52A3-98F3-1221F538819C'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"2A2D5BA8-6AC6-52A3-98F3-1221F538819C","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Cable Press On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your knees at a 90-degree angle.","Hold the cable handles at chest height with your palms facing down and your elbows bent.","Engage your core and press the cable handles forward until your arms are fully extended.","Pause for a moment, then slowly release the tension and bring the cable handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D91C201C-F9A1-5F57-9587-86DC5E1EC317","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"F86AEA0E-8098-599B-B7D4-DE7A78E23F01","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('26C36A62-39DA-559E-8FCD-7945C044A792'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Cable","hint":"","id":"26C36A62-39DA-559E-8FCD-7945C044A792","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Cable Pull Through (With Rope)","notes":"","plannedSets":3,"proTips":["Stand facing away from the cable machine with your feet shoulder-width apart.","Grab the rope attachment with both hands and step forward, creating tension in the cable.","Bend at the hips and lower your upper body until it is parallel to the ground, keeping your back straight.","Engage your glutes and hamstrings to pull your body back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"CC720A0A-51C0-5CD4-8B98-AA2265136941","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"26C14C90-047C-5B2F-B4F2-DCB327A88900","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B3E87401-72AA-58A7-9415-2232D85C9CAE'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"B3E87401-72AA-58A7-9415-2232D85C9CAE","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Cable Pulldown","notes":"","plannedSets":3,"proTips":["Adjust the cable pulldown machine so that the seat is at a comfortable height and the knee pad is secured.","Sit on the seat with your back straight and your feet flat on the ground.","Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and engage your core.","Pull the cable bar down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"DE8B4BCE-8A41-5108-BB6E-32CBB5B05293","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"D2B7DC7C-3E3A-59D8-BF00-4FCAAEB080E8","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4B2BCFF4-2092-592C-B4B1-3067B2B642DD'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"4B2BCFF4-2092-592C-B4B1-3067B2B642DD","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Cable Pulldown (Pro Lat Bar)","notes":"","plannedSets":3,"proTips":["Adjust the seat height so that your thighs are parallel to the ground and your feet are flat on the floor.","Grasp the lat bar with an overhand grip, slightly wider than shoulder-width apart.","Sit down and lean back slightly, keeping your chest up and your back straight.","Pull the bar down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"A73D6ED1-8C83-55A0-9162-0DD98DADC978","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"767EC078-B637-5FD8-89FB-41B50BA988FF","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('18EE7A5D-5267-5DA1-BFFB-0DA762F058D4'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"18EE7A5D-5267-5DA1-BFFB-0DA762F058D4","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Pulldown Bicep Curl","notes":"","plannedSets":3,"proTips":["Attach a straight bar to the cable machine at the highest setting.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and slowly curl the bar down towards your thighs, keeping your wrists straight.","Pause for a moment at the bottom of the movement, squeezing your biceps.","Inhale and slowly return the bar to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"BEC3C154-22F0-5E72-9F1E-D5DD15EAD84D","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B229F27C-3787-5FEA-AEA3-5A97CAC2F0BB","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('780C1554-4A11-5DEC-BF08-FB66CE3B2F35'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"780C1554-4A11-5DEC-BF08-FB66CE3B2F35","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Cable Pushdown","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the bar with an overhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and push the bar down until your elbows are fully extended.","Pause for a moment, then inhale and slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"FD43814E-7DC8-5AAC-8024-0D5B10ECD1EE","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"AA2D2B8E-EF73-56A0-A254-0D6272270F35","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9781659D-3BEC-5724-94CC-062D8B579349'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"9781659D-3BEC-5724-94CC-062D8B579349","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Triceps","Shoulders"],"name":"Cable Pushdown (Straight Arm) V. 2","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down.","Engage your core and keep your back straight as you exhale and push the bar down towards your thighs.","Pause for a moment at the bottom, then slowly return the bar to the starting position while inhaling.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"84ACD60E-C29A-58C7-BEE4-BC2E64B6A833","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"526DC97A-4EDF-55D4-8804-012CD72FA470","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DC46C312-450A-5F5E-B301-C62B6D22F109'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"DC46C312-450A-5F5E-B301-C62B6D22F109","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Cable Pushdown (With Rope Attachment)","notes":"","plannedSets":3,"proTips":["Attach a rope attachment to a high pulley on a cable machine.","Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the rope with an overhand grip, palms facing each other.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Exhale and push the rope downward by extending your elbows until your arms are fully extended.","Pause for a moment, then inhale and slowly return to the starting position by allowing your elbows to flex.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"6C216191-5DB2-5D00-BDE7-0165FDEC0390","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"68A92A57-1E2A-51B1-8E26-ED9E3F8FD9A0","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9E6D0A87-CE3D-546B-809D-9A6CF8BD7E15'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"9E6D0A87-CE3D-546B-809D-9A6CF8BD7E15","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids","Biceps"],"name":"Cable Rear Delt Row (Stirrups)","notes":"","plannedSets":3,"proTips":["Attach a stirrup handle to a low cable pulley and stand facing the machine.","Grasp the handle with your left hand and take a step back with your right foot, positioning your body at a slight angle.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.","With your left arm extended and your palm facing down, pull the handle towards your chest by retracting your shoulder blade.","Pause for a moment at the top of the movement, squeezing your shoulder blade.","Slowly release the handle back to the starting position and repeat for the desired number of repetitions.","Switch sides and repeat the exercise with your right arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B35CD5E5-5D8D-54EF-ACFE-3B833E7966E4","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"521AE732-74C0-5A6B-AA3F-A5348D12748C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CCFB2A68-CAF2-52C4-8595-07844E807204'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"CCFB2A68-CAF2-52C4-8595-07844E807204","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids","Biceps"],"name":"Cable Rear Delt Row (With Rope)","notes":"","plannedSets":3,"proTips":["Attach a rope handle to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope handle with an overhand grip, palms facing each other.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Keep your elbows slightly bent and pull the rope towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"714DD52E-7399-552F-9E0D-27F67F85F00B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"2D5B2FFB-0415-5BD2-BB29-D2EDADCD5A91","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('57DF391E-54EF-5F2C-ABC3-2E5785F0B161'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"57DF391E-54EF-5F2C-ABC3-2E5785F0B161","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders","Back"],"name":"Cable Rear Drive","notes":"","plannedSets":3,"proTips":["Attach a handle to a low pulley cable machine and stand facing away from the machine.","Grasp the handle with an overhand grip and extend your arms straight out in front of you.","Keeping your elbows stationary, pull the handle back towards your body, squeezing your triceps at the end of the movement.","Slowly return the handle to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"6E3586E2-45F6-517A-97D0-172B402133DC","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"452A68AF-AA4B-566E-963E-922620F43181","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4F0C9B93-A7F4-5812-8C75-6FFFE207F709'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"4F0C9B93-A7F4-5812-8C75-6FFFE207F709","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Cable Rear Pulldown","notes":"","plannedSets":3,"proTips":["Adjust the cable machine so that the pulley is at the highest position.","Sit facing the machine with your feet flat on the ground and your knees slightly bent.","Grasp the cable attachment with an overhand grip, hands slightly wider than shoulder-width apart.","Lean back slightly, keeping your back straight and your chest up.","Pull the cable attachment down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the cable back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"BEF16656-0A8C-50EF-874F-8B483AD208C0","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"72375251-01AD-51D9-AA3B-2ED8DEBB9EB5","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B16BD265-347B-5A0B-BEE8-49BE3BDC730C'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"B16BD265-347B-5A0B-BEE8-49BE3BDC730C","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Cable Reverse Crunch","notes":"","plannedSets":3,"proTips":["Attach a cable to a low pulley and lie down facing up on a mat.","Hold the cable with both hands and extend your arms straight up towards the ceiling.","Bend your knees and lift your legs up, bringing your thighs towards your chest.","While keeping your upper body stable, curl your pelvis up towards your chest, lifting your hips off the mat.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"AA5420C2-B76E-53F3-A6CD-0D897EBA3904","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B9BB1A38-011C-5D02-8606-F9AB34AA2C14","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('95B752D6-381C-5CDD-8EB7-1023478F81C1'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"95B752D6-381C-5CDD-8EB7-1023478F81C1","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Reverse Curl","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and your knees slightly bent.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Exhale and curl the bar up towards your shoulders, contracting your biceps.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"C43A5AD7-00D2-57FB-BF51-7B9629FFBF1A","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C44016E4-C256-5F64-9BB5-607F10AE02EB","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6CA1845C-D4DD-5D11-8F98-A3CA38E255F3'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"6CA1845C-D4DD-5D11-8F98-A3CA38E255F3","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Cable Reverse Grip Triceps Pushdown (Sz-Bar) (With Arm Blaster)","notes":"","plannedSets":3,"proTips":["Attach a straight bar to the cable machine at the highest setting.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Engage your triceps and slowly push the bar down until your arms are fully extended.","Pause for a moment at the bottom, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"2B9FA0FF-C402-58F2-979F-6E71FE240404","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"89236E20-B02E-5D00-80C7-58FE0B11B849","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F8C18D7B-597E-5B86-8B49-46C35CBCB1FD'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"F8C18D7B-597E-5B86-8B49-46C35CBCB1FD","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Reverse One Arm Curl","notes":"","plannedSets":3,"proTips":["Stand facing a cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip, palm facing down.","Keep your elbow close to your side and slowly curl your forearm up towards your shoulder.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"09149635-843C-5D66-B2B8-C257899D4713","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"2143C987-5054-5721-9F0D-F72B4AAED868","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CADCEB63-2B57-56F2-8829-530309304C45'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"CADCEB63-2B57-56F2-8829-530309304C45","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Reverse Preacher Curl","notes":"","plannedSets":3,"proTips":["Adjust the cable machine so that the preacher curl pad is at chest height.","Sit on the preacher curl bench and place your upper arms on the pad, with your palms facing down and your elbows fully extended.","Grab the cable handles with an underhand grip, shoulder-width apart.","Keeping your upper arms stationary, exhale and curl the handles towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position, fully extending your elbows.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"EF32A604-F3E0-5C98-ADEE-5277E467C3BF","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"D6994D40-79B0-53A8-A4C3-883A1BEB1F7B","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3FC9795A-43F0-5BA8-BECC-79391A53D46D'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"3FC9795A-43F0-5BA8-BECC-79391A53D46D","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Wrists"],"name":"Cable Reverse Wrist Curl","notes":"","plannedSets":3,"proTips":["Attach a cable to a low pulley and sit on a bench facing the cable machine.","Grasp the cable handle with an overhand grip, palms facing down.","Rest your forearms on your thighs, with your wrists hanging off the edge.","Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.","Pause for a moment at the top, then inhale and slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"6B601F6F-AF4B-5B9E-8730-EA51DA08D396","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"D623304B-B894-5723-892A-A9F0EF80064D","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F58B0697-5DD2-5CAB-BD9B-8BBFD9436744'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"F58B0697-5DD2-5CAB-BD9B-8BBFD9436744","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Cable Reverse-Grip Pushdown","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Using your triceps, push the bar down until your arms are fully extended and your triceps are contracted.","Pause for a moment, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"00F5B84B-3BAE-50EA-ADD5-1CDC8EB60F45","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"49BE7D3E-7F8A-590D-8B22-BD1A3D229E53","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FD205A5F-3793-5910-85C0-4711136D6BEA'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"FD205A5F-3793-5910-85C0-4711136D6BEA","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Reverse-Grip Straight Back Seated High Row","notes":"","plannedSets":3,"proTips":["Sit on the seat facing the cable machine with your feet flat on the floor.","Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your back straight and lean slightly forward from your hips.","Pull the cable towards your torso by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"81A795B8-F2E7-5049-A429-FD76FC97D84F","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"BD983DDD-77E7-5A65-9A3E-B153BA3EEBCB","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('37E4CB36-A848-5E6B-99DF-7313AAADB741'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"37E4CB36-A848-5E6B-99DF-7313AAADB741","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Rope Crossover Seated Row","notes":"","plannedSets":3,"proTips":["Sit on the rowing machine with your feet flat on the footrests and your knees slightly bent.","Grasp the cable ropes with an overhand grip, palms facing each other.","Lean back slightly, keeping your back straight and your core engaged.","Pull the cable ropes towards your chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"FEEAB7AB-41F7-5F76-91C6-8CE38299B1B5","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"278D5C8D-AFBE-5F0C-90F8-A9C5D2A4E343","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7EA14E89-C061-5EB2-8B9D-5E05DE72669D'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"7EA14E89-C061-5EB2-8B9D-5E05DE72669D","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Rope Elevated Seated Row","notes":"","plannedSets":3,"proTips":["Sit on the elevated seat facing the cable machine.","Grab the cable rope handles with an overhand grip, palms facing each other.","Keep your back straight and lean slightly back, maintaining a slight bend in your knees.","Pull the cable towards your body by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the fully contracted position.","Slowly release the tension and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"279A074C-AADB-599C-988A-F5939DDA44EE","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"6C0C5889-CD88-5770-A700-51BE2EA9E96E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3DBC35CB-467A-5CE6-B588-1D8C43F580B1'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"3DBC35CB-467A-5CE6-B588-1D8C43F580B1","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Cable Rope Extension Incline Bench Row","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle and attach a cable machine to the low pulley.","Attach a rope handle to the cable machine and sit on the incline bench facing the machine.","Grab the rope handle with an overhand grip and lean forward, keeping your back straight.","Extend your arms fully, pulling the rope towards your upper chest while keeping your elbows close to your body.","Squeeze your shoulder blades together at the end of the movement.","Slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"46757942-66C7-567D-B8A2-0657BF592F09","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"A09F20B9-0466-54D9-89A0-EE903C42916C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('442A1DF7-8D23-5555-8FD5-D3AF9AD733B7'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"442A1DF7-8D23-5555-8FD5-D3AF9AD733B7","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Rope Hammer Preacher Curl","notes":"","plannedSets":3,"proTips":["Attach a rope attachment to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with a neutral grip (palms facing each other).","Position your upper arms against the preacher bench pad, keeping your elbows slightly bent.","Keeping your upper arms stationary, exhale and curl the rope towards your shoulders by contracting your biceps.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the rope back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B49CF1F9-ACF4-5F71-8BD3-1C00E97EDDBE","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"FA304AB3-380C-576D-B3A1-BB507703F761","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2F5870FF-A01B-5CD9-9C4E-0F07E9793649'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Cable","hint":"","id":"2F5870FF-A01B-5CD9-9C4E-0F07E9793649","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Rope High Pulley Overhead Tricep Extension","notes":"","plannedSets":3,"proTips":["Attach a rope to a high pulley and adjust the weight accordingly.","Stand facing away from the pulley machine with your feet shoulder-width apart.","Grasp the rope with both hands, palms facing down, and bring your hands above your head.","Keep your upper arms close to your head and perpendicular to the floor.","Slowly lower the rope behind your head by bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"8A0BC8AC-6197-5DAA-915B-CEF63F65C663","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4551AE34-9F5E-561B-8899-D1902631CC67","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BEFE571A-BEF6-5168-B419-5000753019AF'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"BEFE571A-BEF6-5168-B419-5000753019AF","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Rope Incline Tricep Extension","notes":"","plannedSets":3,"proTips":["Attach a rope to a high pulley and adjust the incline bench to a comfortable angle.","Stand facing away from the pulley with your feet shoulder-width apart.","Grasp the rope with an overhand grip and extend your arms straight overhead.","Keep your elbows close to your head and your upper arms stationary throughout the exercise.","Lower the rope behind your head by bending your elbows until your forearms touch your biceps.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"44F7F25A-C5F6-58C4-829B-7A4E4E2EE8E3","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"E0C90E00-FC27-52FF-AE25-6B53998C3D30","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2665A699-0BB0-50CD-8FA4-5B710873D892'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"2665A699-0BB0-50CD-8FA4-5B710873D892","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Rope Lying On Floor Tricep Extension","notes":"","plannedSets":3,"proTips":["Attach a rope to a cable machine and set it to the lowest position.","Lie on the floor facing up, with your head towards the cable machine.","Hold the rope with both hands, palms facing each other, and extend your arms straight up towards the ceiling.","Keep your upper arms stationary and slowly lower the rope towards your forehead, bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"DF04DF27-C3D1-58D2-9E3F-7508C7158C6F","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"2F374F91-12F5-5CEE-A39A-F4CD2EF1AA62","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1E35B079-E1C1-53D1-AABF-6B7350ED96B7'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"1E35B079-E1C1-53D1-AABF-6B7350ED96B7","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Rope One Arm Hammer Preacher Curl","notes":"","plannedSets":3,"proTips":["Attach a rope handle to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope handle with an underhand grip, palms facing up.","Position your upper arm against the preacher bench pad, keeping your elbow slightly bent.","Keep your back straight and your core engaged throughout the exercise.","Slowly curl the rope handle towards your shoulder, keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the rope handle back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"64AF72E1-6F1C-51F3-AF86-80248C428FB4","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"838DF543-EA57-5E71-8FD3-0BA318BB0B1F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('26D49B98-762B-5E76-9CA2-D20551415045'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"26D49B98-762B-5E76-9CA2-D20551415045","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Rope Seated Row","notes":"","plannedSets":3,"proTips":["Sit on the rowing machine with your feet flat on the footrests and knees slightly bent.","Grasp the cable ropes with an overhand grip, palms facing each other.","Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows.","Pull the cable ropes towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"EE551223-525F-5457-B192-CEE82A896ED9","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"3C8981B6-EC96-5207-A2B4-A9E200DEF0A6","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F9540893-CB46-509E-BD44-6D05F2892A7C'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"F9540893-CB46-509E-BD44-6D05F2892A7C","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Cable Russian Twists (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold the cable handle with both hands and extend your arms straight out in front of you.","Lean back slightly while keeping your back straight and your core engaged.","Twist your torso to the right, bringing the cable handle towards your right hip.","Pause for a moment, then twist your torso to the left, bringing the cable handle towards your left hip.","Continue alternating twists for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"08E076B8-F49E-59F2-B1CF-BBA061A93AE4","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"90F2C7B4-E563-5409-86C3-89DB9FDB3F88","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7DBEBDAC-C5E5-5374-9290-F952430384AD'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"7DBEBDAC-C5E5-5374-9290-F952430384AD","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Cable Seated Chest Press","notes":"","plannedSets":3,"proTips":["Adjust the seat height and cable handles to a comfortable position.","Sit on the bench with your back straight and feet flat on the floor.","Grasp the cable handles with an overhand grip at shoulder height.","Push the handles forward and away from your body, extending your arms fully.","Pause for a moment, then slowly bring the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"63496E7A-83F3-5DCA-93D0-1D7E087BF021","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"FA2BC32B-9AAC-52FA-98B3-7DB6982D284E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E7F3D77A-9D1A-528D-9C56-177AD08CE0A1'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"E7F3D77A-9D1A-528D-9C56-177AD08CE0A1","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Cable Seated Crunch","notes":"","plannedSets":3,"proTips":["Sit on a cable machine with your feet flat on the ground and your knees bent.","Hold the cable handle with both hands and position it behind your head.","Engage your abs and slowly curl your upper body forward, bringing your chest towards your knees.","Pause for a moment at the top, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"7C1E9DFA-34F7-5046-960E-A6D0492E58A6","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B7948CE2-ED57-5502-A061-E90EE2A34657","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DB461863-CF99-5C3A-9AE7-1A9D900E8D41'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"DB461863-CF99-5C3A-9AE7-1A9D900E8D41","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Seated Curl","notes":"","plannedSets":3,"proTips":["Sit on a cable machine with your feet flat on the ground and your back straight.","Grasp the cable attachment with an underhand grip, palms facing up, and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"FD84B78C-73DA-563B-8715-2351C7F4721B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"DC045861-7AEA-58CA-9BDD-F33794F0BADA","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('931BC2E7-8589-5441-889C-294EC5CAC6CC'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"931BC2E7-8589-5441-889C-294EC5CAC6CC","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Cable Seated High Row (V-Bar)","notes":"","plannedSets":3,"proTips":["Sit on the cable machine with your feet flat on the floor and your knees slightly bent.","Grasp the v-bar attachment with an overhand grip, palms facing each other, and your hands shoulder-width apart.","Keep your back straight and lean slightly forward from the hips.","Pull the v-bar towards your torso by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the peak of the contraction, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"1326D8C3-21C6-5A35-951F-EA2F2A9B1DC6","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"F2D72656-99DF-5B6B-8DA0-3D83E959A77E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('48E3AA58-0909-5F33-BB25-5744E33F36BC'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"48E3AA58-0909-5F33-BB25-5744E33F36BC","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Seated One Arm Alternate Row","notes":"","plannedSets":3,"proTips":["Sit on a bench facing a cable machine with your feet flat on the ground and knees slightly bent.","Grasp the handle with one hand and keep your arm fully extended in front of you.","Pull the handle towards your body, retracting your shoulder blade and keeping your elbow close to your side.","Pause for a moment at the top of the movement, squeezing your back muscles.","Slowly release the handle back to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"7F5DB133-1904-5A20-9C82-F6F95CBBA982","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"381F0FE4-9A04-5B4B-B8E8-CA418948C10A","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AB600697-A09E-586B-8648-3918009B4600'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"AB600697-A09E-586B-8648-3918009B4600","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Seated One Arm Concentration Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the floor and your back straight.","Hold a cable handle with one hand and place your elbow on the inside of your thigh, just above the knee.","Keep your upper arm stationary and curl the cable handle towards your shoulder while exhaling.","Pause for a moment at the top of the movement, squeezing your biceps.","Slowly lower the cable handle back to the starting position while inhaling.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"12938E75-D396-58B4-9E42-95C714BC072A","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"5E6AA080-4F50-5AB9-9126-F21994E267C2","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('978FEBF0-054D-5A9B-9D3E-F23CBA935800'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Cable","hint":"","id":"978FEBF0-054D-5A9B-9D3E-F23CBA935800","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Cable Seated Overhead Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench facing the cable machine with your feet flat on the ground.","Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your upper arms stationary and your elbows close to your sides.","Exhale and curl the cable attachment towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"3AA873C6-C98E-5AD7-BA7A-5438DD97C4C9","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"096C12EC-52D7-5C5C-8CE7-EA1B884FF414","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('26B4FEF4-F54D-5B67-BC3D-0F1B34F349D5'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"26B4FEF4-F54D-5B67-BC3D-0F1B34F349D5","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rhomboids"],"name":"Cable Seated Rear Lateral Raise","notes":"","plannedSets":3,"proTips":["Sit on a bench facing the cable machine with your feet flat on the ground.","Grasp the cable handles with an overhand grip and extend your arms straight in front of you.","Keeping your arms straight, slowly raise them out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"DB7B7223-5203-55B3-B978-981C43DFCB13","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C9359FD5-E4C6-5B72-B35A-7DD89221F182","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8DFCDAF5-C52D-5CB8-8032-B1D12D4259E2'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"8DFCDAF5-C52D-5CB8-8032-B1D12D4259E2","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Seated Row","notes":"","plannedSets":3,"proTips":["Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handles with an overhand grip, keeping your back straight and your shoulders relaxed.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"954546AD-1AAE-55BE-80AD-2B205BA20A78","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"3781A58F-9FE5-5C18-80FE-3B854F713EF9","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E379BFD5-B29E-5772-B4BE-58ADB5283B76'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"E379BFD5-B29E-5772-B4BE-58ADB5283B76","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Rotator Cuff","Triceps"],"name":"Cable Seated Shoulder Internal Rotation","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair facing the cable machine with your feet flat on the ground.","Hold the cable handle with your arm extended straight out in front of you, parallel to the ground.","Keep your elbow slightly bent and your shoulder blades pulled back and down.","Slowly rotate your arm inward, bringing the cable handle towards the center of your body.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"A4F7823F-F3F7-538E-83D1-CF93ED4FEAA9","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('BF90E8F8-4DE7-5579-A015-78171C2BFE7E'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"BF90E8F8-4DE7-5579-A015-78171C2BFE7E","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Cable Seated Twist","notes":"","plannedSets":3,"proTips":["Sit on a cable machine with your feet flat on the ground and your knees slightly bent.","Hold the cable handle with both hands and extend your arms straight in front of you.","Keeping your core engaged, slowly rotate your torso to one side, pulling the cable across your body.","Pause for a moment at the end of the range of motion, then slowly rotate back to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D620C1BB-EEFC-5697-9139-8580AE93C608","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"BA4C893B-D253-51F7-9F72-A4C4ADDC9AC9","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('84AFDAA5-A640-584C-9236-BE1F388E4923'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"84AFDAA5-A640-584C-9236-BE1F388E4923","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cable Seated Wide-Grip Row","notes":"","plannedSets":3,"proTips":["Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handle with a wide overhand grip, palms facing down.","Keep your back straight and lean slightly forward from the hips.","Pull the handle towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the contraction.","Slowly release the handle back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B819F693-990C-53FF-A0E5-F52DE4ABCD53","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"1BE01DEA-E202-5AF9-9534-D1F6F849A75E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('27373472-32F8-5FDD-BADA-F2086E3C9226'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"27373472-32F8-5FDD-BADA-F2086E3C9226","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Cable Shoulder Press","notes":"","plannedSets":3,"proTips":["Adjust the cable machine so that the handles are at shoulder height.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and bring them up to shoulder level, with your elbows bent and pointing outwards.","Press the handles upwards until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the handles back down to shoulder level.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D7A0643C-E392-5C54-A9AE-DFBF298879FD","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"1EF01FC9-5B56-5A43-A913-D7329F90CDFB","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('17029958-E756-55FC-9155-F877D2A5EA34'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"17029958-E756-55FC-9155-F877D2A5EA34","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders"],"name":"Cable Shrug","notes":"","plannedSets":3,"proTips":["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handles with an overhand grip and let your arms hang down in front of you.","Keeping your arms straight, shrug your shoulders up towards your ears.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"85148A8A-A695-5D3E-BE9A-C7653E120713","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"4BF0CEBF-A848-57F9-BEBD-E1C92998321F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2FFE825D-E230-50DA-B93E-720BF6E324CB'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"2FFE825D-E230-50DA-B93E-720BF6E324CB","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Cable Side Bend","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and grasp the cable handle with one hand.","Keep your back straight and your core engaged.","Slowly bend sideways at the waist, lowering the cable handle towards your knee.","Pause for a moment, then return to the starting position.","Repeat on the other side.","Alternate sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"1C25AF4C-7603-5D65-960A-BA7C177DB880","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"6A177DBA-D2E6-5309-ACC3-E6746EE88D67","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F9C3CA48-93F5-5636-9815-7D0592D58D15'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"F9C3CA48-93F5-5636-9815-7D0592D58D15","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Cable Side Bend Crunch (BOSU Ball)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a cable handle in one hand.","Place the other hand on your hip.","Engage your core and slowly bend sideways towards the hand holding the cable, keeping your back straight.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"80E69CD2-453F-569A-B127-E204ED631440","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"5891AE84-5246-5ED2-B583-41D4CC077636","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7512FF48-2ECA-535D-841E-A0E6C9DB8984'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"7512FF48-2ECA-535D-841E-A0E6C9DB8984","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Cable Side Crunch","notes":"","plannedSets":3,"proTips":["Attach a cable handle to a low pulley and stand sideways to the machine.","Grasp the handle with the hand furthest from the machine and place your other hand on your hip.","Keep your feet shoulder-width apart and your knees slightly bent.","With your abs engaged, bend sideways at the waist, bringing your elbow down towards your hip.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"8A946528-9485-51FB-9833-B1D7AEFD06ED","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"0D584A05-9B5B-5CCF-8E82-FFB9CC8E0066","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5E048C6D-6CA9-500D-9F8D-22F5642DE867'::uuid, '{"category":"Back","difficulty":"Advanced","equipment":"Cable","hint":"","id":"5E048C6D-6CA9-500D-9F8D-22F5642DE867","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Cable Squat Row (With Rope Attachment)","notes":"","plannedSets":3,"proTips":["Attach a rope to a cable machine at waist height.","Stand facing the cable machine with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position, keeping your back straight and chest up.","Grasp the rope with an overhand grip, with your hands shoulder-width apart.","Engage your core and pull the rope towards your body, squeezing your shoulder blades together.","Keep your elbows close to your body and continue pulling until your hands reach your chest.","Pause for a moment at the top of the movement, then slowly release the rope and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"CD8C0FB3-C94D-537E-A131-321458A4BE22","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"5882B754-319F-5A28-9763-241BA955529A","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FE566136-1F4B-5B57-8A84-0DB65420C6AC'::uuid, '{"category":"Arms","difficulty":"Advanced","equipment":"Cable","hint":"","id":"FE566136-1F4B-5B57-8A84-0DB65420C6AC","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Squatting Curl","notes":"","plannedSets":3,"proTips":["Attach a cable handle to the lowest setting on a cable machine.","Stand facing the machine with your feet shoulder-width apart.","Hold the cable handle with an underhand grip, palms facing up, and arms fully extended.","Lower your body into a squat position, keeping your back straight and knees behind your toes.","As you squat down, curl the cable handle towards your shoulders, keeping your elbows close to your sides.","Pause for a moment at the top of the curl, squeezing your biceps.","Slowly lower the cable handle back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"9B0813F5-790B-539A-BD2A-94CAADEA23DF","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"6B5353CA-F025-57DA-911E-F8EACCD46B1F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('33BC59BC-9DD6-524C-AADA-088083D6DE8E'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"33BC59BC-9DD6-524C-AADA-088083D6DE8E","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Cable Standing Back Wrist Curl","notes":"","plannedSets":3,"proTips":["Stand facing a cable machine with your feet shoulder-width apart.","Hold the cable handle with an overhand grip, palms facing down.","Keep your arms straight and your elbows close to your sides.","Slowly curl your wrists upward, bringing the cable handle towards your body.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"6BCACCEA-B911-51CB-BD32-4E890AFDF757","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"A617F614-3BA0-5D10-8596-D013EFEA518C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1A304D68-30DB-5EF7-B090-B1D7BA46B339'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Cable","hint":"","id":"1A304D68-30DB-5EF7-B090-B1D7BA46B339","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Cable Standing Calf Raise","notes":"","plannedSets":3,"proTips":["Stand facing a cable machine with your feet shoulder-width apart.","Hold onto the cable machine handles or attach a cable ankle strap to your ankles.","Raise your heels off the ground by extending your ankles as high as possible.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"6132B023-B797-55E5-8A38-073C2167331C","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"3603338A-7E3A-5581-8676-131F8246AB54","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('86629C36-D99F-5081-9B85-AB3E8A5B1FEC'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"86629C36-D99F-5081-9B85-AB3E8A5B1FEC","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids","Rear Deltoids"],"name":"Cable Standing Cross-Over High Reverse Fly","notes":"","plannedSets":3,"proTips":["Attach a D-handle to each side of a cable machine at shoulder height.","Stand in the middle of the cable machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and extend your arms out to the sides, palms facing forward.","Keep a slight bend in your elbows and maintain a straight back throughout the exercise.","Engage your shoulder muscles and squeeze your shoulder blades together as you pull the handles towards the front of your body.","Pause for a moment at the peak of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"7753B03C-D5C3-5AF5-9BBA-6C1EBEFC0648","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"1349CEFD-7F03-5429-9BB8-5F3A02FC9DCF","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5E8D86F8-C924-538F-A4A5-755E5B9917C6'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"5E8D86F8-C924-538F-A4A5-755E5B9917C6","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Cable Standing Crunch","notes":"","plannedSets":3,"proTips":["Attach a cable handle to a high pulley and stand facing away from the machine.","Hold the handle with both hands and place it behind your head, keeping your elbows bent.","Stand with your feet shoulder-width apart and your knees slightly bent.","Keeping your abs engaged, exhale and crunch your torso down towards your knees, bringing your elbows towards your thighs.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"1E7C7647-1C4B-572A-B1C2-9318A70E1A7B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"5EF8A3F2-2E09-5484-A3AA-5BB5D05DF030","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D2838FCC-3EF2-5151-A04D-9CF3B726A7DA'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"D2838FCC-3EF2-5151-A04D-9CF3B726A7DA","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Cable Standing Crunch (With Rope Attachment)","notes":"","plannedSets":3,"proTips":["Attach a rope to a cable machine at chest height.","Stand facing away from the machine with your feet shoulder-width apart.","Hold the rope with both hands and bring it behind your head, keeping your elbows bent.","Engage your abs and slowly crunch your torso forward, bringing your elbows towards your knees.","Pause for a moment at the top of the crunch, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"C5B3E4DF-9956-5DC7-8D4E-D50BA4B24389","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"727E16FD-E26F-5E9E-9710-6306F8650595","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F5A9870A-2896-5418-A89A-45A6767A5D9A'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"F5A9870A-2896-5418-A89A-45A6767A5D9A","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable Standing Fly","notes":"","plannedSets":3,"proTips":["Attach the handles to the cables at chest height.","Stand with your feet shoulder-width apart, facing away from the cable machine.","Grasp the handles with an overhand grip, palms facing forward.","Step forward slightly to create tension in the cables.","Keep your core engaged and your back straight throughout the exercise.","With a slight bend in your elbows, slowly bring your arms forward and together in front of your chest.","Squeeze your chest muscles at the peak of the movement.","Slowly reverse the movement, returning your arms to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"20DCCA9C-31DD-53FB-90C4-29662D197D5B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"10DB419D-EB05-5AFE-A656-C4DA8E6018E6","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6995867A-5429-53F2-9DD3-8F32754D9EFF'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Cable","hint":"","id":"6995867A-5429-53F2-9DD3-8F32754D9EFF","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Cable Standing Hip Extension","notes":"","plannedSets":3,"proTips":["Attach a cable to a low pulley and stand facing away from the machine.","Place the cable around your ankle and stand with your feet shoulder-width apart.","Keep your core engaged and your back straight throughout the exercise.","Slowly extend your leg straight back, squeezing your glutes at the top of the movement.","Pause for a moment, then return to the starting position.","Repeat for the desired number of repetitions.","Switch sides and repeat with the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"9036621C-79AE-5C1D-9488-117835475EE5","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"F865E1BC-8970-552F-AA06-A1E28C46FEB0","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7C3FCCC7-0570-5A36-A228-23FEFE9647BE'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"7C3FCCC7-0570-5A36-A228-23FEFE9647BE","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Standing Inner Curl","notes":"","plannedSets":3,"proTips":["Stand facing a cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip, palms facing up.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the cable handle towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"95239F26-F41D-5112-82BB-B8BD73A70AFE","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"0D1A5FE2-2D49-5C2A-9C34-AD3A17F51839","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FD0D6501-2EE9-51E4-BD43-9FC6D6378571'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"FD0D6501-2EE9-51E4-BD43-9FC6D6378571","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Cable Standing Lift","notes":"","plannedSets":3,"proTips":["Stand facing the cable machine with your feet shoulder-width apart.","Hold the cable handle with both hands and position it at waist height.","Engage your core and maintain a straight back throughout the exercise.","Keeping your arms straight, exhale and lift the cable handle up towards your opposite shoulder, rotating your torso.","Pause for a moment at the top, then inhale and slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"27DE7F75-DCFC-5718-A7FE-447B913E882B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"1B02C51F-F3F6-5A95-B88D-18F36BAA1DF3","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1A34FD35-3B33-5B92-85DA-461EF4633E3F'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"1A34FD35-3B33-5B92-85DA-461EF4633E3F","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Standing One Arm Triceps Extension","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with your right hand, palm facing down, and position your arm so that it is fully extended and parallel to the ground.","Keep your elbow stationary and close to your body.","Slowly bend your elbow, lowering the cable handle towards the back of your head.","Pause for a moment at the bottom of the movement, then extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch sides and perform the exercise with your left arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"72F2E17A-CC3F-52FE-979F-563A60E7892A","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"BDE0D3A2-FBA3-5F47-A617-82DF4E040FF6","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D36E97AC-12F2-5DA8-AD9F-8F46F94E5DDB'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Cable","hint":"","id":"D36E97AC-12F2-5DA8-AD9F-8F46F94E5DDB","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles","Feet"],"name":"Cable Standing One Leg Calf Raise","notes":"","plannedSets":3,"proTips":["Stand facing a cable machine with your feet shoulder-width apart.","Hold onto the cable machine for support.","Lift one leg off the ground and balance on the other leg.","Slowly raise your heel off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"537F4882-372F-5F46-9934-D31A1263BB83","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"AE1D70A2-D75E-5AF6-8A5C-749FC23D67A8","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('452B5E17-3A4A-5A74-890D-07C5998C23AE'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"452B5E17-3A4A-5A74-890D-07C5998C23AE","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Cable Standing Pulldown (With Rope)","notes":"","plannedSets":3,"proTips":["Attach a rope to the cable machine at the highest setting.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with an overhand grip, palms facing down.","Keep your back straight and core engaged throughout the exercise.","Pull the rope down towards your thighs, squeezing your biceps.","Pause for a moment at the bottom, then slowly release the rope back up.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"7475D3ED-ACD2-5DD2-8221-ECD62F95BAEC","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"5A992DFB-DED7-55C2-8281-B62D3289AAA2","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('738FEE25-F95C-5C77-801D-E2D310C8AC1D'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"738FEE25-F95C-5C77-801D-E2D310C8AC1D","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids","Biceps"],"name":"Cable Standing Rear Delt Row (With Rope)","notes":"","plannedSets":3,"proTips":["Stand facing a cable machine with your feet shoulder-width apart.","Hold the cable attachment with both hands, palms facing each other, and step back to create tension in the cable.","Keep your back straight and your core engaged.","Pull the cable towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the cable back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"F1BD56A4-D429-5559-B48B-B4E32F5539C8","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B9E1FD92-9B75-5BCA-8A9F-ADADAD046B12","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A03033AC-C2E3-5E27-8A29-2122D7BFFAEC'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Cable","hint":"","id":"A03033AC-C2E3-5E27-8A29-2122D7BFFAEC","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Standing Reverse Grip One Arm Overhead Tricep Extension","notes":"","plannedSets":3,"proTips":["Stand facing away from the cable machine with your feet shoulder-width apart.","Hold the cable handle with an underhand grip and extend your arm overhead, keeping your elbow close to your head.","Keep your upper arm stationary and slowly lower the cable handle behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"488989BE-2D98-50F4-84DC-B3532F878075","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"E3B76183-5D29-5449-9E09-C6B9A5FE243F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('328E4D39-0E10-59D1-9D6B-6517FC525F32'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"328E4D39-0E10-59D1-9D6B-6517FC525F32","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Cable Standing Row (V-Bar)","notes":"","plannedSets":3,"proTips":["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar attachment with an overhand grip, palms facing down.","Keep your back straight and your core engaged.","Pull the v-bar towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"52A2313A-7AA6-5758-88B1-F2E1B9C0B71F","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B7D0A40C-F757-559E-92FC-712CC31A0B8D","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('22B7C0CE-47F5-5253-833C-9FB5EF64DCD2'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"22B7C0CE-47F5-5253-833C-9FB5EF64DCD2","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Rotator Cuff","Trapezius"],"name":"Cable Standing Shoulder External Rotation","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Hold the cable handle with your arm extended in front of you, parallel to the ground.","Keep your elbow slightly bent and your shoulder blades pulled back.","Slowly rotate your arm outward, away from your body, while keeping your elbow in the same position.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"70F4B1DD-91B1-5F5D-80B9-BFFED40B297C","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('67B5689E-F182-537A-9D74-913F4D3AC6AF'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"67B5689E-F182-537A-9D74-913F4D3AC6AF","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Cable Standing Twist Row (V-Bar)","notes":"","plannedSets":3,"proTips":["Attach a v-bar attachment to a cable machine at chest height.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar with an overhand grip, palms facing down.","Take a step back to create tension in the cable.","Keep your back straight and core engaged throughout the exercise.","Pull the v-bar towards your torso by retracting your shoulder blades and bending your elbows.","As you pull, twist your torso to one side, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, feeling the contraction in your upper back.","Slowly release the tension and return to the starting position, untwisting your torso.","Repeat the movement for the desired number of repetitions, alternating the twisting direction with each rep."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"A8EF5916-4B71-5BCB-9509-BFACE48170F5","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C455FADB-E17E-578E-8F48-AADD78D35350","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2B6ED8A0-34B7-5174-B73B-838119A028EB'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"2B6ED8A0-34B7-5174-B73B-838119A028EB","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable Standing Up Straight Crossovers","notes":"","plannedSets":3,"proTips":["Stand in the middle of a cable machine with your feet shoulder-width apart.","Hold the handles of the cables with your palms facing down and your arms extended straight out to the sides.","Keeping your arms straight, bring your hands together in front of your body, crossing them over each other.","Pause for a moment, then slowly return to the starting position, keeping your arms extended.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"0545CD06-D779-5B77-BBFA-5D9C7DEFFBB4","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"97F61246-5475-5EAA-A49E-96EE819B0D7E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4A8EB60A-672C-5526-8BDB-54F86D991734'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"4A8EB60A-672C-5526-8BDB-54F86D991734","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Biceps"],"name":"Cable Straight Arm Pulldown","notes":"","plannedSets":3,"proTips":["Attach a straight bar to the high pulley of a cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down.","Engage your lats and pull the bar down towards your thighs, keeping your arms straight throughout the movement.","Pause for a moment at the bottom, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"92F53B04-DC87-597D-AB7C-B5AD2E0D6541","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"46D47F80-22A7-5609-BC0C-39B70129613E","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0C641076-0197-5307-B68D-61932E99378B'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"0C641076-0197-5307-B68D-61932E99378B","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Cable Straight Arm Pulldown (With Rope)","notes":"","plannedSets":3,"proTips":["Attach a rope to the cable machine at the highest setting.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with both hands, palms facing down.","Extend your arms fully in front of you, keeping your elbows slightly bent.","Engage your lats and slowly pull the rope down towards your thighs, keeping your arms straight.","Pause for a moment at the bottom, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D8D500B4-61F5-5B9A-BE4C-868074714660","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"154FAB6C-047F-5298-84F0-0A329F44C85F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B6733BFB-AFFF-54B4-BE31-C476CFC94524'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"B6733BFB-AFFF-54B4-BE31-C476CFC94524","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms","Shoulders"],"name":"Cable Straight Back Seated Row","notes":"","plannedSets":3,"proTips":["Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.","Grasp the cable handles with an overhand grip, palms facing down.","Keep your back straight and lean slightly forward from the hips.","Pull the cable handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"A5A6501B-2370-555C-8141-4C0372EB5409","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"BF065830-2B5B-5721-B576-6E867DC2AA61","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('371E3E05-96A9-5D93-BC6E-000CF31D3F65'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"371E3E05-96A9-5D93-BC6E-000CF31D3F65","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids"],"name":"Cable Supine Reverse Fly","notes":"","plannedSets":3,"proTips":["Attach a D-handle to a low pulley cable machine and lie face down on a flat bench.","Grasp the D-handle with each hand, palms facing down, and extend your arms straight out in front of you.","Keeping your arms straight, raise them out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"1E0E1E13-ECD4-5A2F-BB67-40963C2C49A9","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"8C7211E5-C1E9-5D47-8B22-897CC122B814","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C54F9CEE-49E4-5905-BDD2-0D497BADE275'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"C54F9CEE-49E4-5905-BDD2-0D497BADE275","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Cable Thibaudeau Kayak Row","notes":"","plannedSets":3,"proTips":["Attach a cable handle to a low pulley and sit facing the machine with your feet flat on the floor.","Grasp the handle with your right hand and extend your arm fully, keeping a slight bend in your elbow.","Lean forward from your hips, keeping your back straight and your abs engaged.","Pull the handle towards your torso by retracting your shoulder blade and bending your elbow, keeping your arm close to your body.","Squeeze your back muscles at the top of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides and perform with your left arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D6F4E3AB-3108-55AA-8087-987B000E9681","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"CA80982E-1919-5796-B386-E40027907C58","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DB64424D-5908-5F97-BEAC-2C2C3B2ECBF7'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"DB64424D-5908-5F97-BEAC-2C2C3B2ECBF7","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Cable Triceps Pushdown (V-Bar)","notes":"","plannedSets":3,"proTips":["Attach a v-bar attachment to the cable machine at the highest setting.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Engage your triceps and exhale as you push the v-bar down until your arms are fully extended.","Pause for a moment at the bottom of the movement, squeezing your triceps.","Inhale as you slowly return the v-bar to the starting position, maintaining control.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"8A48AE89-876B-5AA6-9684-3FA488550A34","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"03B2C967-E40C-5745-B2BE-9E7D9108240F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('91C730D7-B990-5F58-96E8-396AFA8D93D1'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"91C730D7-B990-5F58-96E8-396AFA8D93D1","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Cable Triceps Pushdown (V-Bar) (With Arm Blaster)","notes":"","plannedSets":3,"proTips":["Attach a v-bar attachment to the cable machine at the highest setting.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Engage your triceps and exhale as you push the v-bar down until your arms are fully extended.","Pause for a moment at the bottom of the movement, squeezing your triceps.","Inhale as you slowly return the v-bar to the starting position, maintaining control.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"68463955-5DF8-5F26-A3B3-C459588F71FC","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"86AC7C95-C02A-5802-A0F7-2E3DD5640C4D","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E584F9B2-C6F4-5A96-8A65-F801B0D897CF'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"E584F9B2-C6F4-5A96-8A65-F801B0D897CF","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Cable Tuck Reverse Crunch","notes":"","plannedSets":3,"proTips":["Attach a cable to a low pulley and lie down on a mat facing up.","Hold the cable with both hands and extend your arms straight up above your chest.","Bend your knees and lift your legs up, bringing your knees towards your chest.","At the same time, curl your pelvis up towards your chest, lifting your hips off the ground.","Pause for a moment at the top, then slowly lower your legs and hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"5ADC15E0-7A8B-53FA-A743-1A7F1573FF33","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"0CEBBDEE-FB80-5997-A24C-D8D1A14E358B","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1C695B9F-8E55-53F6-9EF7-D02CBE8B5CEC'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"1C695B9F-8E55-53F6-9EF7-D02CBE8B5CEC","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Cable Twist","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent.","Engage your core and twist your torso to the right, pulling the cable across your body.","Pause for a moment at the end of the movement, feeling the contraction in your abs and obliques.","Slowly return to the starting position, resisting the cable''s pull.","Repeat the movement to the left side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"53515F0D-4899-5E36-9017-BEA93590BF89","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"474A85E0-3F76-5CAB-B417-BA1A10702F4C","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C061EA70-E272-5B3D-B41E-EF9034D2C3A5'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Cable","hint":"","id":"C061EA70-E272-5B3D-B41E-EF9034D2C3A5","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Cable Twist (Up-Down)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent.","Engage your core and slowly rotate your torso to one side, keeping your hips and legs stable.","Pause for a moment at the end of the rotation, then slowly return to the starting position.","Repeat the rotation to the opposite side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"25C1C438-F2E4-533A-A28C-E2018F850D9B","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"611BF8B2-B091-5528-9097-E52AE20E4979","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D09566E9-FB0D-5096-96FE-F171B2578839'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"D09566E9-FB0D-5096-96FE-F171B2578839","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Biceps"],"name":"Cable Twisting Pull","notes":"","plannedSets":3,"proTips":["Attach a cable handle to a low pulley and stand facing the machine.","Grasp the handle with your left hand and step away from the machine, extending your arm fully.","Position your feet shoulder-width apart, with your knees slightly bent.","Keep your back straight and your core engaged throughout the exercise.","Pull the handle towards your body, rotating your torso to the right as you do so.","Squeeze your back muscles at the end of the movement.","Slowly return to the starting position, keeping tension on the cable.","Repeat for the desired number of repetitions, then switch sides and perform with your right hand."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"BECEF49C-DECA-521D-8DF8-1C8DBA9F0DD2","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"60F70CE1-EC6B-5221-ABEA-B4425CCF7DFF","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('01DF2DB6-1C2D-55FA-AE47-ED09CF32EC3A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"01DF2DB6-1C2D-55FA-AE47-ED09CF32EC3A","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Cable Two Arm Curl On Incline Bench","notes":"","plannedSets":3,"proTips":["Sit on an incline bench with your back against the pad and your feet flat on the ground.","Grasp the cable handles with an underhand grip, palms facing up, and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the handles towards your shoulders while contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"0B4BE8CE-DB72-5228-AC09-57E68131AE03","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"67F06F92-1373-56A9-B81C-2C84CE212295","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A2E94DC4-A6B7-50B7-A4CE-BC2C409C2784'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"A2E94DC4-A6B7-50B7-A4CE-BC2C409C2784","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Cable Two Arm Tricep Kickback","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the cable handle in each hand with your palms facing inwards and your arms bent at a 90-degree angle.","Keeping your upper arms stationary, extend your forearms backwards until your arms are fully extended.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"ECD0F5D9-FB28-5B0F-99D3-EE0CB34586D7","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"B8700A74-10DE-50B3-AE5B-117AC3C0D3C5","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('19C8D930-E628-54E1-82ED-61327A6C37C8'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"19C8D930-E628-54E1-82ED-61327A6C37C8","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Cable Underhand Pulldown","notes":"","plannedSets":3,"proTips":["Adjust the cable machine so that the pulldown bar is at a height above your head.","Sit down on the seat and grab the pulldown bar with an underhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and lean back slightly.","Pull the bar down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"095BFC5F-B714-5FCE-B22E-E7891BF18C14","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"9A6B85B7-6229-51B4-A92D-47DB90DFC7BE","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5633B786-E965-53CB-BEA0-259FD58054F4'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Cable","hint":"","id":"5633B786-E965-53CB-BEA0-259FD58054F4","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Cable Upper Chest Crossovers","notes":"","plannedSets":3,"proTips":["Attach the handles to the cables at chest height.","Stand in the center of the cable machine with one foot slightly in front of the other.","Grasp the handles with your palms facing down and your arms extended out to the sides.","Keep a slight bend in your elbows and engage your core.","Pull the cables together in front of your chest, crossing them over each other.","Squeeze your chest muscles at the peak of the movement.","Slowly release the cables back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"AF22B48F-D3A4-536B-90E8-035307E8FAAC","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"36F0E18D-7BB3-5E35-98EF-DBF7718B3E29","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('404C17BC-34F5-562D-9350-94CAFFB18AE9'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"404C17BC-34F5-562D-9350-94CAFFB18AE9","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Cable Upper Row","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a cable machine at chest height.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and your core engaged.","Pull the bar towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"17D4795E-2355-5810-9D72-DCBA3D787368","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"EC498BB0-92A5-53CC-9B70-0658FBD99DAD","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BB24112A-401D-5159-A279-2396229D6ADD'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Cable","hint":"","id":"BB24112A-401D-5159-A279-2396229D6ADD","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Biceps"],"name":"Cable Upright Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, knees slightly bent, and hold the cable attachment with an overhand grip.","Keep your back straight and your core engaged throughout the exercise.","Pull the cable attachment straight up towards your chin, leading with your elbows.","Pause for a moment at the top, squeezing your shoulder blades together.","Slowly lower the cable attachment back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"D9A13599-1695-5DB9-9003-7F2CB5CF9F64","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"35B91AA2-ED45-5D4A-B1EE-828C986B7EA7","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('41603D68-8844-5913-97E7-EA49177C58C0'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"41603D68-8844-5913-97E7-EA49177C58C0","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Cable Wide Grip Rear Pulldown Behind Neck","notes":"","plannedSets":3,"proTips":["Adjust the cable machine so that the pulldown bar is at a height above your head.","Sit down on the seat and grab the pulldown bar with a wide overhand grip.","Keep your back straight and your chest up as you lean back slightly.","Pull the bar down towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"7A1E9DAB-61E7-5F46-A80F-39E2EA340BE6","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"D09673E9-8BEB-5872-B7FC-3FDB968F0026","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('19424738-CEB6-59EC-963E-61A50B0F9E87'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Cable","hint":"","id":"19424738-CEB6-59EC-963E-61A50B0F9E87","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Cable Wrist Curl","notes":"","plannedSets":3,"proTips":["Attach a straight bar to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.","Rest your forearms on a bench or pad, with your wrists hanging off the edge.","Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.","Pause for a moment at the top, then inhale and slowly lower the bar back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"C4218866-A5E7-5777-9C00-487ECA41FD30","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"61AB6909-35CB-5F00-A425-067178993FE1","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('29A4D222-8D4D-55D4-BE8E-99FDB5135836'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"29A4D222-8D4D-55D4-BE8E-99FDB5135836","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Calf Push Stretch With Hands Against Wall","notes":"","plannedSets":3,"proTips":["Stand facing a wall with your feet hip-width apart.","Place your hands against the wall at shoulder height.","Step back with one foot, keeping your heel on the ground and your leg straight.","Bend your front knee slightly and lean forward, feeling a stretch in your calf.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"FC178D80-812B-5DDC-8BCD-16D3E352DC81","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('C9A3DE7A-9219-5CE8-A107-8ADBBAFB0C66'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C9A3DE7A-9219-5CE8-A107-8ADBBAFB0C66","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Calf Stretch With Hands Against Wall","notes":"","plannedSets":3,"proTips":["Stand facing a wall with your feet hip-width apart.","Place your hands against the wall at shoulder height.","Step your right foot back, keeping your heel on the ground and your leg straight.","Bend your left knee and lean forward, keeping your back leg straight and your heel on the ground.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"7589F409-181D-5286-9C6E-6FB1B8A47E1F","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('09EE74D1-9DD3-540F-A3A2-0933E63ECB52'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Rope","hint":"","id":"09EE74D1-9DD3-540F-A3A2-0933E63ECB52","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Calf Stretch With Rope","notes":"","plannedSets":3,"proTips":["Stand facing a wall or sturdy object with your feet hip-width apart.","Hold the ends of the rope in each hand and place the middle of the rope around the ball of your right foot.","Step back with your left foot, keeping your heel on the ground and your leg straight.","Lean forward, keeping your back straight, and gently pull on the rope to stretch your calf.","Hold the stretch for 20-30 seconds, then release.","Repeat on the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"EB113B90-5991-57C3-8CF3-2A387055CF96","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('A458FC38-BEEB-581F-B1C0-94D50B4B2E6D'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Barbell","hint":"","id":"A458FC38-BEEB-581F-B1C0-94D50B4B2E6D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Cambered Bar Lying Row","notes":"","plannedSets":3,"proTips":["Set up a barbell on the floor and lie face down on a bench with your chest just off the edge.","Reach down and grab the barbell with an overhand grip, slightly wider than shoulder-width apart.","With your legs straight and feet on the ground, lift the barbell off the floor by extending your arms.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"1385F9D4-0894-5E2B-B0D9-3567665F210A","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"EEC3E66A-8C3E-50DB-9371-34662EFC40D7","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"072C0A3C-1B08-5E2D-9A77-D224AA69245C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"C16540C4-B81C-5ED0-8C11-4366B19FB79C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8F66C44F-CC3C-5EEB-A5E0-5E7944F0B7D0'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"8F66C44F-CC3C-5EEB-A5E0-5E7944F0B7D0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Captains Chair Straight Leg Raise","notes":"","plannedSets":3,"proTips":["Sit on the captain''s chair with your back against the backrest and your forearms resting on the arm pads.","Keep your upper body stable and your back straight.","Engage your abs and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"909C46E3-048E-5F13-9B79-79BAFEA1B47B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('02A9413F-928A-525F-8ECC-69F66821B66E'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"02A9413F-928A-525F-8ECC-69F66821B66E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings","Calves"],"name":"Chair Leg Extended Stretch","notes":"","plannedSets":3,"proTips":["Sit on the edge of a chair with your back straight and feet flat on the ground.","Extend one leg straight out in front of you, keeping your heel on the ground.","Lean forward slightly, feeling a stretch in your quadriceps.","Hold this position for 20-30 seconds.","Switch legs and repeat the stretch."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"8DD9AB1C-041B-5338-99E7-F4E3DC808C8A","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('3458A5FA-52F5-50C2-B95E-1904F56476A9'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3458A5FA-52F5-50C2-B95E-1904F56476A9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids"],"name":"Chest And Front Of Shoulder Stretch","notes":"","plannedSets":3,"proTips":["Stand tall with your feet shoulder-width apart.","Extend your arms straight out in front of you at shoulder height.","Cross your arms in front of your body, with your right arm on top of your left arm.","Interlace your fingers and press your palms together.","Gently squeeze your shoulder blades together and push your hands forward, feeling a stretch in your chest and front of your shoulders.","Hold the stretch for 20-30 seconds, then release.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"62C91C46-2EB8-5CD7-87A2-DB4E02B33215","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('E496985A-362A-5AF8-BFDE-0C78D391C5E5'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E496985A-362A-5AF8-BFDE-0C78D391C5E5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Chest Dip","notes":"","plannedSets":3,"proTips":["Position yourself on parallel bars with your arms fully extended and your body straight.","Lower your body by bending your elbows until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6816140E-FCD1-55E5-BEAD-0AB15C2A4DBB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CA33C0DE-E152-5551-BE14-9DD76DD651AB'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"CA33C0DE-E152-5551-BE14-9DD76DD651AB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Chest Dip (On Dip-Pull-Up Cage)","notes":"","plannedSets":3,"proTips":["Adjust the dip bars to a height that allows you to comfortably grip them.","Stand between the bars and place your hands on each bar, slightly wider than shoulder-width apart.","Jump up and straighten your arms, supporting your body weight on the bars.","Bend your knees and cross your ankles behind you.","Lower your body by bending your elbows, keeping your chest up and your shoulders down.","Continue lowering until your shoulders are below your elbows or until you feel a stretch in your chest.","Push through your palms and extend your elbows to raise your body back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"589ED58D-8162-5C09-9750-07FA5F0157CE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3019F174-34EC-5511-B483-0B70AFAE35C0'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3019F174-34EC-5511-B483-0B70AFAE35C0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Chest Dip On Straight Bar","notes":"","plannedSets":3,"proTips":["Grab the parallel bars with your palms facing down and your arms fully extended.","Bend your knees and cross your ankles.","Lower your body by bending your arms until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"27BF69CE-0511-588B-B81C-1FE837040F67","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CB93420D-2314-57ED-9874-E9988080B9D7'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"CB93420D-2314-57ED-9874-E9988080B9D7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Chest Stretch With Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on the stability ball with your feet flat on the ground and your back straight.","Hold the exercise ball with both hands and extend your arms straight out in front of you.","Slowly bring the exercise ball towards your chest, feeling a stretch in your chest muscles.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"CF3FCE45-8A16-572A-86A8-B47FE5366C84","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('AEB8A659-4F8E-5D91-BE84-4BCA66D2D3EB'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"AEB8A659-4F8E-5D91-BE84-4BCA66D2D3EB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Chest Tap Push-Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you lower yourself, tap your chest with your right hand.","Push yourself back up to the starting position.","Repeat the movement, this time tapping your chest with your left hand.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CFAA45F1-00C4-5F66-A73F-898496AE9798","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('38CA1708-B134-501E-B3C7-619BE46FD224'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"38CA1708-B134-501E-B3C7-619BE46FD224","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Chin-Up","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Engage your core and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AECAF124-400D-5500-A17B-00522CEFC644","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('12D746C6-C420-599F-A6A0-93AA151E216D'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"12D746C6-C420-599F-A6A0-93AA151E216D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Chin-Ups (Narrow Parallel Grip)","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with a narrow parallel grip, palms facing towards you.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E57180FE-1F0C-5745-A73E-AFF1F9B72DBB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C96148A1-7D3F-538A-97E7-01E24D508990'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C96148A1-7D3F-538A-97E7-01E24D508990","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Quadriceps"],"name":"Circles Knee Stretch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your hands on your hips.","Bend your knees slightly and lift your heels off the ground, balancing on the balls of your feet.","Keeping your knees bent, rotate your knees in a circular motion, first clockwise and then counterclockwise.","Perform the movement for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"D1344892-2E9F-5256-BA95-053A10271A1F","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('701849BE-2728-585F-8683-FDEB5F18E85E'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"701849BE-2728-585F-8683-FDEB5F18E85E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Clap Push Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your body towards the ground by bending your elbows, keeping your core engaged.","Push through your palms explosively to propel your body off the ground.","While in mid-air, clap your hands together before landing back in the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"99A5114B-9A3F-5A8F-A025-86E9C2CD5E39","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('66097554-1878-5875-80F0-8771E122A547'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"66097554-1878-5875-80F0-8771E122A547","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Clock Push-Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you lower, rotate your body to the left, extending your left arm straight out to the side.","Push back up to the starting position, while rotating your body to the center.","Repeat the push-up, this time rotating your body to the right and extending your right arm out to the side.","Continue alternating sides with each repetition."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FC2131AF-C46B-5FC5-8AA3-43778641DB29","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('65F40E56-156B-5F3D-AC89-EAD7472896B4'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"65F40E56-156B-5F3D-AC89-EAD7472896B4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Close Grip Chin-Up","notes":"","plannedSets":3,"proTips":["Grab the pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Hang from the bar with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0A9194A6-34F0-5951-A347-B838A88BE1CF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C2946B93-D763-5911-9625-7E3F3E32ABF5'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"C2946B93-D763-5911-9625-7E3F3E32ABF5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Close-Grip Push-Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands placed close together, directly under your shoulders.","Engage your core and lower your body towards the ground, keeping your elbows close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"10B3E3E3-11DC-5778-970B-D499E1B8C379","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('33BF138C-9945-5AF6-B147-A2DCA697A757'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"33BF138C-9945-5AF6-B147-A2DCA697A757","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Close-Grip Push-Up (On Knees)","notes":"","plannedSets":3,"proTips":["Start by getting on your hands and knees, with your hands shoulder-width apart and your knees hip-width apart.","Lower your upper body towards the ground by bending your elbows, keeping them close to your sides.","Pause for a moment when your chest is just above the ground.","Push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B3267AAC-EB8B-5DCA-8AFA-CCF94E583835","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BF9CCD51-9C6B-5268-B7A1-93259F29121A'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"BF9CCD51-9C6B-5268-B7A1-93259F29121A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Cocoons","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"ADB2200F-D5A9-5C5C-9FBA-171B8A975B75","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B150490B-65C5-504D-B5FC-4F6B62E411AE'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B150490B-65C5-504D-B5FC-4F6B62E411AE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Hip Flexors"],"name":"Crab Twist Toe Touch","notes":"","plannedSets":3,"proTips":["Start by sitting on the ground with your knees bent and feet flat on the floor.","Place your hands behind you, fingers pointing towards your feet, and lift your hips off the ground.","Extend one leg straight out in front of you while simultaneously reaching your opposite hand towards your toes.","Return to the starting position and repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"934ACA4C-980E-5A38-954A-6A747F3B5856","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B4C90C97-0796-5D1F-B32B-675BAE492775'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B4C90C97-0796-5D1F-B32B-675BAE492775","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Cross Body Crunch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your upper body off the ground and twist to bring your right elbow towards your left knee.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat on the other side, bringing your left elbow towards your right knee.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AA9502BE-2444-53EF-9EAA-D53601A7894C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E6B45BDB-9772-5B9E-B254-596B10FD1192'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Bodyweight","hint":"","id":"E6B45BDB-9772-5B9E-B254-596B10FD1192","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Crunch (Hands Overhead)","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms straight above your head.","Engaging your abs, lift your upper body off the ground, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3AF4035E-94A0-5E75-9337-654E43F9D1AD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('932C2DE4-EECA-5799-AE4F-97AC1F7B8034'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"932C2DE4-EECA-5799-AE4F-97AC1F7B8034","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Crunch (On Stability Ball)","notes":"","plannedSets":3,"proTips":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Lie back on the ball until your lower back is supported and your upper body is parallel to the floor.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body towards your knees, curling your torso forward.","Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"719BD3B0-B234-5B36-8C60-45C1B90DE248","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F04895A1-8D53-5037-92C7-30A6F79C50D1'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"F04895A1-8D53-5037-92C7-30A6F79C50D1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Crunch (On Stability Ball, Arms Straight)","notes":"","plannedSets":3,"proTips":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Lie back on the ball until your lower back is supported and your upper body is parallel to the floor.","Place your hands behind your head or cross them over your chest.","Engage your abs and lift your upper body off the ball, curling your shoulders towards your hips.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A2CCC211-E9D2-5BA6-97E7-D38C04136D59","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A4281245-1287-58F1-8A4C-305DF1BE7004'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A4281245-1287-58F1-8A4C-305DF1BE7004","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Crunch Floor","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lift your shoulders off the ground, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2DF82AAA-BD6B-5C91-B4A1-434D03D3FE32","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FB0DFC7F-B4C1-5C52-A2D5-0939A13AD7EC'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"FB0DFC7F-B4C1-5C52-A2D5-0939A13AD7EC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Curl-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DC612305-AFFF-59EA-8446-1F0E6A4685A0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AFFB1917-C252-5C4B-B472-DFF825DE105C'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"AFFB1917-C252-5C4B-B472-DFF825DE105C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Curtsey Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Take a step diagonally behind and across your body with your right foot, crossing it behind your left leg.","Bend both knees as if you were curtsying, lowering your body towards the ground.","Keep your torso upright and your weight on your front foot.","Push through your front foot to return to the starting position.","Repeat on the other side, stepping diagonally behind and across your body with your left foot."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"37504016-2CDD-527D-B4B6-F64651EFB7EC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E6306BDD-5D9C-52EB-A9A0-DB3A866F613D'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Machine","hint":"","id":"E6306BDD-5D9C-52EB-A9A0-DB3A866F613D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Glutes"],"name":"Cycle Cross Trainer","notes":"","plannedSets":3,"proTips":["Adjust the seat height and position yourself on the cycle cross trainer.","Place your feet on the pedals and grip the handlebars.","Start pedaling in a smooth and controlled motion.","Maintain a steady pace and increase the resistance if desired.","Continue pedaling for the desired duration of your cardio workout."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('771E4A1B-E9E3-5411-B2D1-1DBFFCE49629'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"771E4A1B-E9E3-5411-B2D1-1DBFFCE49629","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Dead Bug","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your arms extended towards the ceiling.","Bend your knees and lift your legs off the ground, creating a 90-degree angle at your hips and knees.","Engage your core and lower back to press your lower back into the ground.","Slowly lower your right arm and left leg towards the ground, keeping them straight and hovering just above the floor.","Pause for a moment, then return to the starting position.","Repeat the movement with your left arm and right leg.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9E4D85AD-3241-50C5-A413-4CA1922FB5C9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7F659F53-A4E8-5E84-8EBC-7E05FEB8A12E'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"7F659F53-A4E8-5E84-8EBC-7E05FEB8A12E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Decline Crunch","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your feet secured and your knees bent at a 90-degree angle.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body towards your knees, curling your torso.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"683DCAD7-C68E-5345-96B6-C0EA4BC7D752","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('62F7C4E5-7735-5B3B-A16E-3BF4FC1E1F78'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"62F7C4E5-7735-5B3B-A16E-3BF4FC1E1F78","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Decline Push-Up","notes":"","plannedSets":3,"proTips":["Place your hands on the ground slightly wider than shoulder-width apart, with your feet elevated on a stable surface.","Keep your body in a straight line from head to toe, engaging your core muscles.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"75B826B6-DE3A-5884-8F6C-A54E22592A99","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DD7DD1EC-3921-5960-AF41-0D2099DB92D6'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"DD7DD1EC-3921-5960-AF41-0D2099DB92D6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Decline Sit-Up","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your feet secured and your knees bent.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body off the bench, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6373E267-48EC-58E7-B1C0-7E31052909AD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('76798D89-9DD3-55F8-89BA-C5FD9BD83ED5'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"76798D89-9DD3-55F8-89BA-C5FD9BD83ED5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Deep Push Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E427D3CD-D210-5045-825F-93FDB05407A4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8EC7D1D0-BF93-5E28-AF9D-0F4739A21B58'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"8EC7D1D0-BF93-5E28-AF9D-0F4739A21B58","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Diamond Push-Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands close together, forming a diamond shape with your thumbs and index fingers.","Keep your body in a straight line from head to toe, engaging your core and glutes.","Lower your chest towards the diamond shape formed by your hands, keeping your elbows close to your body.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2E772F5B-BEB4-5100-A505-9328F4189C10","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('174AF30B-6117-5125-94DE-6D6AAD702B93'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"174AF30B-6117-5125-94DE-6D6AAD702B93","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Donkey Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your toes on an elevated surface, such as a step or block.","Place your hands on a stable support, such as a wall or railing, for balance.","Raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F7148CFD-0AB1-57F7-8BAA-027560C17148","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2C6A6793-5128-5EBA-AC56-B94767D90A4F'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"2C6A6793-5128-5EBA-AC56-B94767D90A4F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Drop Push Up","notes":"","plannedSets":3,"proTips":["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your chest towards the ground, keeping your elbows close to your body.","Once your chest is just above the ground, quickly drop your knees to the ground.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E458A652-4EB2-50D1-BC6E-857279FEC4C7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2B6AB418-701D-53FD-B7D8-0D370D3A6D2F'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"2B6AB418-701D-53FD-B7D8-0D370D3A6D2F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Alternate Biceps Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions, alternating arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"EE31BA39-D0CD-5A0D-AADF-6E0A4044921D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1C03025A-5279-5731-A08C-A9A285889C4D'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"1C03025A-5279-5731-A08C-A9A285889C4D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Alternate Biceps Curl (With Arm Blaster)","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Place the arm blaster on your upper arms, ensuring a secure fit.","Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with the opposite arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"14B06127-ADAB-5999-8AEA-0DBA8604D2F2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C9E36D11-3FDD-5003-B452-CDD07B6EE71D'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"C9E36D11-3FDD-5003-B452-CDD07B6EE71D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Alternate Hammer Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher bench with a dumbbell in each hand, palms facing your torso and arms fully extended.","Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"15538E87-7A77-5DB9-9F4A-22F0579C2E9A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('97CDCBC5-84CE-5BF6-993E-61E3B49EE8AB'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"97CDCBC5-84CE-5BF6-993E-61E3B49EE8AB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Alternate Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher bench with a dumbbell in each hand, palms facing up.","Rest your upper arms on the pad of the preacher bench, allowing your arms to fully extend.","Keeping your upper arms stationary, exhale and curl the dumbbell in your right hand as you contract your biceps.","Continue to curl the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Pause for a moment, then inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with your left arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"24A5D462-85D0-50A1-81B4-D92314B1FEBD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('422323B9-BC7A-59DB-83BB-9FCC6B71E515'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"422323B9-BC7A-59DB-83BB-9FCC6B71E515","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Alternate Seated Hammer Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended down.","Keep your back straight and your elbows close to your torso.","Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Pause for a brief moment, then inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with your left arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6E009E4F-A782-54D2-9D2F-BBAC853D94EC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B51F1173-93DE-5402-8C27-FF11FF01293A'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B51F1173-93DE-5402-8C27-FF11FF01293A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Dumbbell Alternate Side Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height.","Press one dumbbell overhead while keeping the other dumbbell at shoulder height.","Lower the pressed dumbbell back to shoulder height while pressing the other dumbbell overhead.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9A1A948A-92F6-5F7A-9335-8E8C10E73973","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F80BC476-BCDA-5C2A-B534-5D701C018ABE'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F80BC476-BCDA-5C2A-B534-5D701C018ABE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Dumbbell Alternating Bicep Curl With Leg Raised On Exercise Ball","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Place an exercise ball behind you and position one foot on top of it, keeping your balance.","With your arms fully extended and elbows close to your sides, curl one dumbbell towards your shoulder while keeping your upper arm stationary.","Lower the dumbbell back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D7204BC2-BDE6-5744-AA24-78870F7E5F19","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7A3B8858-66B3-5F00-99C0-1653D29A43EB'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7A3B8858-66B3-5F00-99C0-1653D29A43EB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Alternating Seated Bicep Curl On Exercise Ball","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Keeping your upper arms stationary, exhale and curl one dumbbell while rotating your forearm until your palm is facing your shoulder.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the curl with the other arm.","Continue alternating curls for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4A13DF19-EA10-53AC-9D5C-85D25BF3683B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2DBA9106-EF04-5514-B721-AFE896C0410A'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"2DBA9106-EF04-5514-B721-AFE896C0410A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Chest"],"name":"Dumbbell Arnold Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent.","Press the dumbbells upward until your arms are fully extended and your palms are facing forward.","Rotate your wrists as you lift, so that your palms are facing forward at the top of the movement.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9C4C49D9-696F-53E1-8CD9-107141DE2A8E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B68FB333-26B8-5D5B-ABC6-A799A965201F'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"B68FB333-26B8-5D5B-ABC6-A799A965201F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Chest"],"name":"Dumbbell Arnold Press V. 2","notes":"","plannedSets":3,"proTips":["Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent.","Press the dumbbells upward until your arms are fully extended and your palms are facing forward.","Rotate your wrists as you lift, so that your palms end up facing forward at the top of the movement.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"B74093CB-446A-57CE-91BD-563C3ECCB0F7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('35E33BC7-DAFB-520B-9900-7EB1B6B90C6F'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"35E33BC7-DAFB-520B-9900-7EB1B6B90C6F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Latissimus Dorsi"],"name":"Dumbbell Around Pullover","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your head at one end and your feet firmly on the ground.","Hold a dumbbell with both hands and extend your arms straight above your chest.","Keeping your arms straight, slowly lower the dumbbell behind your head in an arc motion.","Pause for a moment at the bottom, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DC2C6168-94BD-5956-B2D4-39BBF4C806D2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FAE02641-DEBD-560C-9DAA-B31D3AB73420'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"FAE02641-DEBD-560C-9DAA-B31D3AB73420","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Dumbbell Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Hold a dumbbell in each hand, with your palms facing forward and your arms extended above your chest.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Pause for a moment, then push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A475FFBC-2966-523B-BBA5-EB6B02E96E5F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('70A2C927-39B1-5B36-B331-6A083A2148A9'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"70A2C927-39B1-5B36-B331-6A083A2148A9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Chest"],"name":"Dumbbell Bench Seated Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with a dumbbell in each hand, resting on your thighs.","Lean back and position the dumbbells to the sides of your chest, palms facing forward.","Press the dumbbells upward until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2EE8F5CE-947E-57DE-A3BA-B7A72AB70986","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AB093606-4345-540C-BD15-45E1D4CE1F2F'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"AB093606-4345-540C-BD15-45E1D4CE1F2F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Dumbbell Bench Squat","notes":"","plannedSets":3,"proTips":["Place a dumbbell on the ground in front of a bench.","Stand facing away from the bench with your feet shoulder-width apart.","Bend at the knees and hips to lower yourself down towards the bench, keeping your chest up and back straight.","Once your glutes touch the bench, push through your heels to stand back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FE494091-F887-5C16-918C-A8DA2E95B09E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9C9675F5-FB11-5B21-8144-908CE434305F'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9C9675F5-FB11-5B21-8144-908CE434305F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Dumbbell Bent Over Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in each hand with your palms facing your body.","Bend forward at the hips, keeping your back straight and your core engaged.","Let your arms hang straight down towards the floor, with your elbows slightly bent.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0F3D3F29-2B85-59E0-900E-16430F31CE2A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F1440E55-837A-5DC1-A744-A8659822A806'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F1440E55-837A-5DC1-A744-A8659822A806","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Dumbbell Bicep Curl Lunge With Bowling Motion","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Take a step forward with your right foot, bending your right knee and lowering your body into a lunge position.","As you lunge forward, curl the dumbbells up towards your shoulders, keeping your elbows close to your body.","At the bottom of the lunge, rotate your torso to the right, as if you were bowling a ball.","Reverse the motion, stepping back with your right foot and returning to the starting position while lowering the dumbbells back down.","Repeat the lunge and curl motion, this time rotating your torso to the left.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2D2B33DC-50AB-5508-9EE9-E778E75AC224","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EA7D2D97-F6E2-513A-8A13-E3E27D6DA553'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"EA7D2D97-F6E2-513A-8A13-E3E27D6DA553","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Dumbbell Bicep Curl On Exercise Ball With Leg Raised","notes":"","plannedSets":3,"proTips":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Slowly curl the dumbbells towards your shoulders, keeping your elbows close to your sides.","Pause for a moment at the top of the movement, then slowly lower the dumbbells back to the starting position.","While performing the bicep curl, raise one leg off the ground and hold it in the air for the duration of the exercise.","Repeat for the desired number of repetitions, then switch legs and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"625DBDAE-9E21-54ED-A7D5-A2C78EE1AA1E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('94059E4D-DC34-52F4-8DA8-C7729D553C24'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"94059E4D-DC34-52F4-8DA8-C7729D553C24","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Bicep Curl With Stork Stance","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Extend one leg behind you, balancing on the toes of that foot.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"441A75A3-4243-57BE-AB36-A60E7E702859","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0B8D4BB8-70F3-5DB6-8E82-3185070D21FF'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"0B8D4BB8-70F3-5DB6-8E82-3185070D21FF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Biceps Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8A085225-4E6E-511C-8FC2-73A9C46E3316","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9E3D8871-8543-5C9A-BAD9-57454A8CA860'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"9E3D8871-8543-5C9A-BAD9-57454A8CA860","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Biceps Curl (With Arm Blaster)","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A8244524-937A-5779-94EC-1C710F51671A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8A0B764E-529A-5963-A013-00755596B5E1'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"8A0B764E-529A-5963-A013-00755596B5E1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Biceps Curl Reverse","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A2EDE426-4D5B-508A-981C-7083EFFD3A54","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8DF5FC46-6D5E-54BF-BD16-82DA5EA1C795'::uuid, '{"category":"Arms","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"8DF5FC46-6D5E-54BF-BD16-82DA5EA1C795","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Biceps Curl Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Keeping your back straight and your elbows close to your sides, exhale and curl the dumbbells up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2EA5CAED-A6A1-5F21-AAC0-0097F5963963","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3A72DFBF-16C6-53B7-B2CD-C1DC43A4378C'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"3A72DFBF-16C6-53B7-B2CD-C1DC43A4378C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Dumbbell Biceps Curl V Sit On BOSU Ball","notes":"","plannedSets":3,"proTips":["Sit on a bosu ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended down by your sides.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CAF68B54-1C67-5D5C-900F-344B0AA270F9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FC03CEAB-F86F-5DA2-A0C9-AACC8B6ACE28'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"FC03CEAB-F86F-5DA2-A0C9-AACC8B6ACE28","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves","Shoulders","Triceps","Core"],"name":"Dumbbell Burpee","notes":"","plannedSets":3,"proTips":["Start in a standing position with your feet shoulder-width apart and a dumbbell in each hand.","Lower your body into a squat position, placing the dumbbells on the ground in front of you.","Kick your feet back into a push-up position, keeping your body in a straight line.","Perform a push-up, bending your elbows and lowering your chest towards the ground.","Jump your feet back towards your hands, landing in a squat position.","Stand up explosively, lifting the dumbbells off the ground and bringing them to your shoulders.","Press the dumbbells overhead, fully extending your arms.","Lower the dumbbells back to your shoulders and repeat the entire sequence for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('7EA2DC12-4E94-5F6E-B3BB-DC722C57A3FD'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"7EA2DC12-4E94-5F6E-B3BB-DC722C57A3FD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Calves"],"name":"Dumbbell Clean","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Bend your knees and lower your hips into a squat position, keeping your back straight and chest up.","Explosively extend your hips and knees, driving through your heels to jump off the ground.","As you jump, shrug your shoulders and pull the dumbbells up towards your shoulders, keeping them close to your body.","Catch the dumbbells at shoulder height, with your elbows pointing forward and your palms facing up.","Lower the dumbbells back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"20BEB364-99E9-587E-BAD5-344BE95B1004","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A018B86D-C3DF-5713-BC15-B7036188EF4A'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"A018B86D-C3DF-5713-BC15-B7036188EF4A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Dumbbell Close Grip Press","notes":"","plannedSets":3,"proTips":["Sit on a flat bench with a dumbbell in each hand, resting on your thighs.","Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest.","As you exhale, use your triceps to lift the dumbbells back to the starting position. Make sure to use only your triceps and do not use your forearms or biceps to help lift the dumbbells.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"846F143D-B6D1-59EE-8865-07E1276B44BD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('30119D82-4052-5ABE-A4A8-0B2380C3DE62'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"30119D82-4052-5ABE-A4A8-0B2380C3DE62","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Dumbbell Close-Grip Press","notes":"","plannedSets":3,"proTips":["Sit on a flat bench with a dumbbell in each hand, resting on your thighs.","Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest.","As you exhale, use your triceps to lift the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9901257B-C538-5111-8BD6-0EB384027BCC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DCADFAF6-26F6-5854-9895-267122C74D11'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"DCADFAF6-26F6-5854-9895-267122C74D11","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Concentration Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your legs spread apart and a dumbbell in one hand, resting your elbow on the inside of your thigh.","Fully extend your arm and hold the dumbbell with an underhand grip.","Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"28E86551-3ACA-5D9C-A385-B2324EFECDC4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('896F3EC7-8F09-5FF5-AA80-34488534B3EF'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"896F3EC7-8F09-5FF5-AA80-34488534B3EF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Dumbbell Contralateral Forward Lunge","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, keeping your back straight and core engaged.","Lower your body by bending both knees until your right thigh is parallel to the ground.","Push through your right heel to return to the starting position.","Repeat with your left leg.","Alternate legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"983EBB4C-AE9D-51CE-BEA9-ABB1AFC098FB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F2EC03AD-8141-57B4-A035-B135905E6070'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F2EC03AD-8141-57B4-A035-B135905E6070","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Cross Body Hammer Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the dumbbells across your body towards your opposite shoulder.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C798A204-BCCF-5840-AAC6-C931790AE30D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('87EA8E7D-EDF8-542E-9195-9E9B4F8D8BA2'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"87EA8E7D-EDF8-542E-9195-9E9B4F8D8BA2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Dumbbell Cross Body Hammer Curl V. 2","notes":"","plannedSets":3,"proTips":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the dumbbells as close to your opposite shoulder as possible.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6CCF6D76-A6A6-54D5-A9B7-E15252C6BD1A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F3DC37D6-E407-5635-B5C3-A5B118402F0D'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"F3DC37D6-E407-5635-B5C3-A5B118402F0D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Dumbbell Cuban Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down.","Keeping your core engaged and your elbows slightly bent, press the dumbbells up and overhead until your arms are fully extended.","Rotate your wrists so that your palms are facing forward.","Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as you do so.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DD2B9E77-FDF4-588A-A7FC-D7F6AF237732","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8641F69C-FA9C-565A-BB08-9209414E1B3C'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"8641F69C-FA9C-565A-BB08-9209414E1B3C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Dumbbell Cuban Press V. 2","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down.","Keeping your core engaged and your back straight, press the dumbbells straight up overhead until your arms are fully extended.","Rotate your wrists so that your palms are facing forward.","Lower the dumbbells back down to shoulder height, rotating your wrists back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CB1F6619-6E9D-5FC5-9F62-47530747C4AA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2E30B63A-216E-5FC3-BAD6-754CBC099182'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Dumbbell","hint":"","id":"2E30B63A-216E-5FC3-BAD6-754CBC099182","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Dumbbell Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes pointing forward.","Hold a dumbbell in each hand, palms facing your body, arms extended downwards.","Bend at your hips and knees, lowering the dumbbells towards the ground while keeping your back straight.","Push through your heels and extend your hips and knees, lifting the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A8048B35-6BFE-5E17-A1FB-F715ADD571AB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('96442F27-73FE-5A59-B606-A3D983BFA9AB'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"96442F27-73FE-5A59-B606-A3D983BFA9AB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Dumbbell Decline Bench Press","notes":"","plannedSets":3,"proTips":["Lie down on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand and extend your arms straight up above your chest, palms facing forward.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8C8D3243-1129-5ECC-88F8-462A9A5D4DE8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6D8991DC-7859-5BD3-A508-22261F4C6D4E'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"6D8991DC-7859-5BD3-A508-22261F4C6D4E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders"],"name":"Dumbbell Decline Fly","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"904C822D-477A-5E27-BC69-2F0A4C50A0C3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('82DFC891-F26A-55B7-9646-F1505F112373'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"82DFC891-F26A-55B7-9646-F1505F112373","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Dumbbell Decline Hammer Press","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells to the sides of your chest, keeping your elbows slightly bent.","Press the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D791B7E2-2876-5003-959D-957C9F2035C3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('453BDACF-CD35-5C5C-9A53-019E14CE6BC0'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"453BDACF-CD35-5C5C-9A53-019E14CE6BC0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders"],"name":"Dumbbell Decline One Arm Fly","notes":"","plannedSets":3,"proTips":["Lie down on a decline bench with a dumbbell in one hand, resting it on your thigh.","Using your thigh to help raise the dumbbell, lift it up to shoulder width with your palm facing your torso.","Rotate your wrist so that the palm of your hand is facing forward.","As you breathe in, lower the dumbbell slowly to the side until you feel a stretch in your chest.","Exhale and use your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9D8A085C-6EE8-557D-95A5-01C849D3396C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('543BDDE6-E300-5ECD-B946-25BA45DE514B'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"543BDDE6-E300-5ECD-B946-25BA45DE514B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Dumbbell Decline One Arm Hammer Press","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with a dumbbell in one hand, resting on your chest.","Extend your arm straight up, keeping your elbow slightly bent.","Lower the dumbbell down towards your shoulder, keeping your elbow close to your body.","Press the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3551AD86-0AF3-5425-8908-9195D64A5E88","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C4759B28-C70A-5FA8-9DA0-C2940CE0B6CF'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Dumbbell","hint":"","id":"C4759B28-C70A-5FA8-9DA0-C2940CE0B6CF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders","Rhomboids"],"name":"Dumbbell Decline Shrug","notes":"","plannedSets":3,"proTips":["Set up a decline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting against it.","Hold a dumbbell in each hand with your arms fully extended towards the floor.","Keeping your arms straight, raise your shoulders towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"EC163295-021A-5B0B-B258-31BD4127E307","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now())
